function scoreLexMentorPatterns(query: string, patterns: RegExp[]) {
  return patterns.reduce((total, pattern) => total + (pattern.test(query) ? 1 : 0), 0)
}

function normalizeLexMentorQuery(query: string) {
  return query.toLowerCase().replace(/[^\p{L}\p{N}\s]/gu, ' ').replace(/\s+/g, ' ').trim()
}

function countIncludedLexMentorTerms(query: string, terms: string[]) {
  return terms.reduce((count, term) => count + (query.includes(term) ? 1 : 0), 0)
}

function getSemanticLegalIntentScore(query: string) {
  const concepts = countIncludedLexMentorTerms(query, legalConceptTerms)
  const subjects = countIncludedLexMentorTerms(query, legalSubjectTerms)
  const tasks = countIncludedLexMentorTerms(query, legalTaskVerbs)
  const indianLegalContext = /\b(india|indian|bharat|supreme court|high court|parliament)\b/i.test(query) ? 1 : 0

  let score = concepts + subjects * 2
  if (tasks > 0 && (concepts > 0 || subjects > 0 || indianLegalContext > 0)) score += 1
  if (indianLegalContext > 0 && (concepts > 0 || subjects > 0)) score += 1
  if (/\bwhat is\b|\bexplain\b|\btell me about\b|\bhow do i\b|\bdraft\b/i.test(query) && (concepts > 0 || subjects > 0)) score += 1
  return score
}

function isLexMentorGreeting(query: string) {
  return greetingPatterns.some((pattern) => pattern.test(normalizeLexMentorQuery(query)))
}

function isLegalDomainQuery(query: string) {
  const normalized = normalizeLexMentorQuery(query)
  if (!normalized) return false
  const legalScore = scoreLexMentorPatterns(normalized, legalDomainPatterns)
  const nonLegalScore = scoreLexMentorPatterns(normalized, nonLegalDomainPatterns)
  const semanticLegalScore = getSemanticLegalIntentScore(normalized)
  const hasBypassAttempt = promptBypassPatterns.some((pattern) => pattern.test(normalized))

  if (hasBypassAttempt && nonLegalScore >= legalScore) return false
  if (semanticLegalScore >= 2 || (semanticLegalScore >= 1 && legalScore > 0)) return true
  if (legalScore > 0 && legalScore >= nonLegalScore) return true
  if (nonLegalScore > 0) return false
  return true
}

function cleanLexMentorConcept(raw: string) {
  return raw
    .replace(/\b(in law|under law|under indian law|legally|please|kindly)\b/gi, ' ')
    .replace(/[?.!]+$/g, '')
    .replace(/\s+/g, ' ')
    .trim()
}

function getLexMentorComparisonParts(query: string): [string, string] | null {
  const normalized = query.replace(/[?]+$/g, '').trim()
  const betweenMatch = normalized.match(/\bdifference between\s+(.+?)\s+and\s+(.+)$/i)
  if (betweenMatch) return [cleanLexMentorConcept(betweenMatch[1]), cleanLexMentorConcept(betweenMatch[2])]

  const distinguishMatch = normalized.match(/\bdistinguish between\s+(.+?)\s+and\s+(.+)$/i)
  if (distinguishMatch) return [cleanLexMentorConcept(distinguishMatch[1]), cleanLexMentorConcept(distinguishMatch[2])]

  const vsMatch = normalized.match(/^(.+?)\s+(?:vs\.?|versus)\s+(.+)$/i)
  if (vsMatch) return [cleanLexMentorConcept(vsMatch[1]), cleanLexMentorConcept(vsMatch[2])]
  return null
}

function getLexMentorDefinitionConcept(query: string) {
  const normalized = query.trim()
  const match = normalized.match(/^(?:what is|what are|who is|who are|define|meaning of|explain|tell me about)\s+(?:a |an |the )?(.+?)\??$/i)
  return match ? cleanLexMentorConcept(match[1]) : ''
}

