function buildLexMentorDefinitionReply(conceptRaw: string) {
  const concept = cleanLexMentorConcept(conceptRaw).toLowerCase()
  const known = lexMentorDefinitions[concept]
  const display = cleanLexMentorConcept(conceptRaw).replace(/\b\w/g, (char) => char.toUpperCase())

  if (known) {
    return `Definition:
${known.definition}

Meaning:
${known.meaning}

Practical Example:
${known.example}

Legal Context:
${known.context}

Related Concepts:
${known.related}`
  }

  return `Definition:
${display} is a legal concept, term, or subject that should be understood by identifying its legal meaning, source, and effect.

Meaning:
In legal analysis, the meaning depends on the jurisdiction, statute, case law, and factual context in which the term is used.

Practical Example:
If ${display} appears in a case problem, you should ask: who is affected, what legal rule applies, what right or duty is created, and what remedy follows?

Legal Context:
Use the relevant statute, constitutional provision, judgment, contract clause, or procedural rule to explain it precisely.

Related Concepts:
Rights, duties, liability, remedy, jurisdiction, procedure, precedent, statutory interpretation.`
}

function buildLexMentorComparisonReply(leftRaw: string, rightRaw: string) {
  const left = cleanLexMentorConcept(leftRaw)
  const right = cleanLexMentorConcept(rightRaw)
  const leftLower = left.toLowerCase()
  const rightLower = right.toLowerCase()

  if ((leftLower.includes('petitioner') && rightLower.includes('respondent')) || (leftLower.includes('respondent') && rightLower.includes('petitioner'))) {
    return `Comparison: Petitioner vs Respondent

Petitioner:
- Starts the case by filing a petition.
- Seeks a legal remedy, direction, writ, or order from the court.
- Must show facts, legal grounds, and requested relief.

Respondent:
- Opposes or answers the petition.
- Defends the challenged action, decision, or legal position.
- Usually files a reply or counter-affidavit.

Example:
If A files a writ petition against a government authority, A is the petitioner and the authority is the respondent.

Exam Note:
Do not confuse petitioner/respondent with plaintiff/defendant. Plaintiff/defendant is common in civil suits, while petitioner/respondent is common in writs, appeals, and petition-based proceedings.`
  }

  if ((leftLower.includes('mens rea') && rightLower.includes('actus reus')) || (leftLower.includes('actus reus') && rightLower.includes('mens rea'))) {
    return `Comparison: Mens Rea vs Actus Reus

Mens Rea:
- The guilty mind or mental element.
- Covers intention, knowledge, recklessness, or negligence depending on the offence.
- Answers: what was the accused's mental state?

Actus Reus:
- The guilty act or external element.
- Covers conduct, omission, result, and circumstances.
- Answers: what prohibited act or omission occurred?

Example:
In a theft-type offence, taking property is actus reus; dishonest intention is mens rea.

Exam Note:
Most crimes require both, but strict liability offences may reduce or remove the mens rea requirement.`
  }

  return `Comparison: ${left} vs ${right}

${left}:
- Identify its legal definition, source, and role in the dispute.
- Ask what right, duty, liability, or remedy it creates.

${right}:
- Identify its separate legal definition, source, and role.
- Ask how its elements, purpose, or consequences differ from ${left}.

Key Differences:
1. Nature: compare what each concept legally means.
2. Function: compare what each concept does in a case or statute.
3. Application: compare the facts needed to apply each concept.
4. Consequence: compare the remedy, liability, or procedural effect.

Exam Note:
Write comparisons element-wise, not as two disconnected definitions.`
}

function buildLexMentorLocalReply(query: string, depth: string) {
  const queryLower = query.toLowerCase().trim()

  if (isLexMentorGreeting(query)) {
    return `Hi, I am LexMentor AIâ„¢.

I can help you with law-related questions such as legal research, case law analysis, bare acts, constitutional law, contracts, legal drafting, moot court preparation, and compliance.

What legal issue would you like to discuss today?`
  }

  if (!isLegalDomainQuery(query)) return LEXMENTOR_REJECTION_RESPONSE

  const comparisonParts = getLexMentorComparisonParts(query)
  if (comparisonParts) return buildLexMentorComparisonReply(comparisonParts[0], comparisonParts[1])

  if (queryLower.includes('law system') || queryLower.includes('legal system') || queryLower.includes('justice system')) {
    return `The legal system in India is based on the Constitution of India, statutes enacted by legislatures, judicial precedents, and principles of justice, equity, and good conscience.

Key features:
1. India follows a common law system, where judgments of higher courts guide lower courts.
2. The Constitution is the supreme law.
3. The Supreme Court is the highest court, followed by High Courts and subordinate courts.
4. Parliament and State Legislatures make statutes within their legislative fields.
5. Judicial review allows courts to test executive and legislative action against the Constitution.

For legal study, understand the Indian system through three pillars: constitutional structure, statutory law, and case law interpretation.`
  }
  if (queryLower.includes('constitution')) {
    return `The Indian Constitution is the supreme legal document of India. It establishes the structure of government, distributes powers, protects fundamental rights, and lays down constitutional values.

Important parts:
1. Preamble: constitutional philosophy.
2. Fundamental Rights: enforceable rights against the State.
3. Directive Principles: governance goals.
4. Fundamental Duties: citizen duties.
5. Federal structure: Union, States, and Concurrent powers.
6. Judiciary: independent courts with judicial review.

For exams, focus on Articles 12-35, 32, 136, 141, 226, 245-254, and 368.`
  }
  if (queryLower.includes('bns')) {
    return `BNS means Bharatiya Nyaya Sanhita, 2023. It is India's new principal penal statute replacing the Indian Penal Code for offences committed after its commencement.

Study it through:
1. General explanations and definitions.
2. General exceptions.
3. Offences against the human body.
4. Offences against property.
5. Offences against the State.
6. Punishments and liability rules.

For criminal law preparation, compare BNS provisions with old IPC concepts such as mens rea, actus reus, culpable homicide, theft, cheating, and common intention.`
  }
  if (queryLower.includes('bnss')) {
    return `BNSS means Bharatiya Nagarik Suraksha Sanhita, 2023. It replaces the Code of Criminal Procedure for criminal procedure after its commencement.

It deals with:
1. Investigation
2. Arrest
3. Bail
4. Trial procedure
5. Jurisdiction of criminal courts
6. Charges
7. Appeals, revision, and execution of sentences

For exams, connect BNSS with BNS and Bharatiya Sakshya Adhiniyam because substantive offence, procedure, and evidence work together in criminal cases.`
  }
  if (queryLower.includes('article 21') || queryLower.includes('liberty')) {
    return `Article 21 of the Constitution of India protects life and personal liberty. The Supreme Court has interpreted it broadly to include dignity, fair procedure, privacy, livelihood, health, and other aspects of meaningful life.

Key legal points:
1. In Maneka Gandhi v. Union of India, the Court held that any procedure affecting personal liberty must be just, fair, and reasonable.
2. In K.S. Puttaswamy v. Union of India, the Court held that privacy is part of Article 21.
3. Article 21 is usually read with Articles 14 and 19, forming the constitutional test against arbitrary state action.

For ${depth} level study, focus on how Article 21 changed from a narrow protection against unlawful detention into a broad guarantee of substantive due process.`
  }
  if (queryLower.includes('basic structure') || queryLower.includes('amend')) {
    return `The Basic Structure Doctrine limits Parliament's power to amend the Constitution under Article 368. Parliament may amend the Constitution, but it cannot destroy its essential identity.

Core features usually discussed include:
1. Supremacy of the Constitution
2. Rule of law
3. Judicial review
4. Democracy
5. Secularism
6. Federalism
7. Separation of powers

Key cases:
1. Kesavananda Bharati v. State of Kerala established the doctrine.
2. Minerva Mills v. Union of India reaffirmed that limited amending power itself is part of the basic structure.`
  }
  if (queryLower.includes('judicial review')) {
    return `Judicial review is the power of courts to examine whether legislative or executive action is consistent with the Constitution and the law.

In India:
1. High Courts exercise writ jurisdiction under Article 226.
2. The Supreme Court protects fundamental rights under Article 32.
3. Courts can strike down unconstitutional laws or arbitrary state action.
4. Judicial review is treated as part of the basic structure of the Constitution.

It preserves constitutional supremacy, rule of law, and limited government.`
  }
  if (queryLower.includes('writ')) {
    return `A writ petition is a constitutional remedy filed before the Supreme Court under Article 32 or a High Court under Article 226.

Main writs:
1. Habeas Corpus: protects personal liberty against illegal detention.
2. Mandamus: commands a public authority to perform a legal duty.
3. Certiorari: quashes illegal orders of courts or tribunals.
4. Prohibition: prevents a lower court or tribunal from exceeding jurisdiction.
5. Quo Warranto: questions illegal occupation of a public office.

High Courts have wider writ powers under Article 226 than the Supreme Court under Article 32.`
  }
  if (queryLower.includes('contract') || queryLower.includes('agreement') || queryLower.includes('indian contract law')) {
    return `Indian Contract Law is mainly governed by the Indian Contract Act, 1872. A contract is an agreement enforceable by law.

Essential elements of a valid contract:
1. Offer and acceptance
2. Lawful consideration
3. Capacity of parties
4. Free consent
5. Lawful object
6. Certainty of terms
7. Intention to create legal relations

Important doctrines:
1. Free consent can be affected by coercion, undue influence, fraud, misrepresentation, or mistake.
2. Agreements with unlawful object or consideration are void.
3. Breach of contract may lead to damages, specific performance, injunction, or other remedies depending on the facts.

If you are studying for exams, start with Sections 2, 10, 11, 13-19, 23, 25, 37, 39, and 73-75 of the Indian Contract Act.`
  }
  if (queryLower.includes('nda')) {
    return `An NDA, or Non-Disclosure Agreement, is a contract used to protect confidential information.

Core clauses usually include:
1. Definition of confidential information
2. Purpose of disclosure
3. Receiving party obligations
4. Exclusions from confidentiality
5. Term and survival
6. Return or destruction of information
7. Injunction and damages
8. Governing law and jurisdiction

If you want, provide parties, purpose, duration, and jurisdiction, and I can draft a structured NDA.`
  }
  if (queryLower.includes('legal research')) {
    return `Legal research is the process of finding, interpreting, and applying legal sources to answer a legal issue.

A strong method:
1. Frame the issue.
2. Identify the jurisdiction.
3. Find primary sources: Constitution, statutes, rules, judgments.
4. Use secondary sources: commentaries, articles, digests.
5. Check whether cases are still good law.
6. Apply authorities to facts.

For law school and practice, always separate binding authority from persuasive authority.`
  }
  if (queryLower.includes('judiciary')) {
    return `For judiciary exam preparation, build your study around bare acts, leading cases, procedural law, and answer writing.

Suggested plan:
1. Read bare acts daily.
2. Prepare core subjects: Constitution, IPC/BNS, CrPC/BNSS, Evidence/BSA, CPC, Contract, Torts, Family Law.
3. Make section-wise notes.
4. Practice previous year questions.
5. Write mains answers with issue-rule-application-conclusion structure.
6. Revise landmark judgments weekly.

Start with high-frequency subjects and revise short notes repeatedly.`
  }
  if (queryLower.includes('moot court')) {
    return `Moot court is a simulated court proceeding where students argue a legal problem before judges.

Main components:
1. Reading the proposition
2. Identifying issues
3. Legal research
4. Memorial drafting
5. Oral arguments
6. Rebuttal and sur-rebuttal

A good moot argument combines facts, law, precedent, and policy in a clear court-style structure.`
  }
  const definitionConcept = getLexMentorDefinitionConcept(query)
  if (definitionConcept) return buildLexMentorDefinitionReply(definitionConcept)

  if (queryLower.includes('law')) {
    return `Law is a system of rules recognized and enforced by the State to regulate conduct, protect rights, impose duties, and resolve disputes.

In legal study, you can understand any law through five questions:
1. What right, duty, liability, or power does it create?
2. Who does it apply to?
3. What conduct is allowed, prohibited, or required?
4. What remedy or penalty follows breach?
5. Which court, tribunal, or authority enforces it?

For a stronger answer, tell me the area of law you want: constitutional law, criminal law, civil law, contract law, corporate law, family law, tax law, labour law, or another legal subject.`
  }
  return `I can help with this legal query, but the live LexMentor AI service should generate the specific answer for this question.`
}


