const getResearchWorkflowIcon = (category: string) => {
  const iconMap: Record<string, any> = {
    "Moot Proposition": FileSearch,
    Memorial: Scale,
    "Research Paper": BarChart3,
    Judgment: Gavel,
    "Bare Act": BookOpen,
    "Legal Brief": PenSquare,
    "User Notes": FolderOpen,
  }
  const Icon = iconMap[category] || FileText
  return <Icon size={17} strokeWidth={2.1} />
}


