  const handleMootCourtUnlock = async (event: FormEvent<HTMLFormElement>) => {
    event.preventDefault()
    if (!isMootCourtOwner) return

    const trimmedPassword = mootCourtPassword.trim()
    if (trimmedPassword.length < 8) {
      setMootCourtLockError('Use at least 8 characters for this private lock.')
      return
    }

    try {
      setMootCourtUnlocking(true)
      setMootCourtLockError('')
      const passwordHash = await hashMootCourtPassword(trimmedPassword)

      if (passwordHash !== MOOT_COURT_PASSWORD_HASH) {
        setMootCourtLockError('Incorrect password.')
        return
      }

      setIsMootCourtUnlocked(true)
      setMootCourtPassword('')
    } catch (error) {
      console.error('Failed to unlock Moot Court Suite:', error)
      setMootCourtLockError('Unable to unlock here. Please try again in this browser.')
    } finally {
      setMootCourtUnlocking(false)
    }
  }

