  const submitExitFeedback = async () => {
    if (!exitFeedbackOption) return;

    let finalDescription = exitFeedbackText;
    const isBug = exitFeedbackOption === 'Found a Bug' || exitFeedbackOption === 'Feature Not Working';

    if (isBug) {
      const pageUrl = window.location.href;
      const activeModule = activeTab;
      const browser = navigator.userAgent;
      const deviceType = /Mobi|Android|iPhone|iPad/i.test(navigator.userAgent) ? 'Mobile' : 'Desktop';
      const timestamp = new Date().toISOString();
      const sessionId = dbUser?.id || clerkUser?.id || 'anonymous-session';

      finalDescription += `\n\n--- Auto-collected Context ---\nURL: ${pageUrl}\nActive Module: ${activeModule}\nBrowser: ${browser}\nDevice Type: ${deviceType}\nTimestamp: ${timestamp}\nSession ID: ${sessionId}`;
    }

    if (exitFeedbackEmail) {
      finalDescription += `\n\nContact Email: ${exitFeedbackEmail}`;
    }

    try {
      const response = await fetch(`${settingsApiBase}/feedback`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${apiToken}`
        },
        body: JSON.stringify({
          type: isBug ? 'bug' : 'feature',
          issueType: exitFeedbackOption,
          module: activeTab || 'General',
          description: finalDescription,
        })
      });
      if (response.ok) {
        setExitFeedbackSubmitted(true);
        setTimeout(() => {
          setShowExitFeedback(false);
        }, 1500);
      }
    } catch (err) {
      console.error('Failed to submit exit feedback:', err);
      setShowExitFeedback(false);
    }
  };

  useEffect(() => {
    let triggered = false;
    const triggerExitIntent = () => {
      if (triggered) return;
      if (window.sessionStorage.getItem('legatrixon_exit_feedback_shown')) return;
      triggered = true;
      window.sessionStorage.setItem('legatrixon_exit_feedback_shown', 'true');
      setShowExitFeedback(true);
    };

    const handleMouseLeave = (e: MouseEvent) => {
      if (e.clientY < 20) {
        triggerExitIntent();
      }
    };
    document.addEventListener('mouseleave', handleMouseLeave);

    const handleVisibilityChange = () => {
      if (document.visibilityState === 'hidden') {
        triggerExitIntent();
      }
    };
    document.addEventListener('visibilitychange', handleVisibilityChange);

    const handlePageHide = () => {
      triggerExitIntent();
    };
    window.addEventListener('pagehide', handlePageHide);

    const handleBeforeUnload = () => {
      triggerExitIntent();
    };
    window.addEventListener('beforeunload', handleBeforeUnload);

    return () => {
      document.removeEventListener('mouseleave', handleMouseLeave);
      document.removeEventListener('visibilitychange', handleVisibilityChange);
      window.removeEventListener('pagehide', handlePageHide);
      window.removeEventListener('beforeunload', handleBeforeUnload);
    };
  }, []);

  const submitRating = async (stars: number) => {
    // Client-side anti-spam check (ratings in the last 2 minutes)
    const recentRating = myFeedbacks?.find(
      (t: any) => (t.ticket_type === 'Star Rating' || t.type === 'rating') && (Date.now() - new Date(t.created_at).getTime()) < 120000
    );
    if (recentRating) {
      setSettingsActionStatus('You have already submitted a rating recently. Please wait a moment.');
      return;
    }

    setStarRating(stars)
    try {
      const response = await fetch(`${settingsApiBase}/feedback`, {
        method: 'POST',
        headers: { 
          'Content-Type': 'application/json',
          Authorization: `Bearer ${apiToken}` 
        },
        body: JSON.stringify({
          type: 'rating',
          rating: stars,
          description: `User rated the platform ${stars} stars.`,
        }),
      })
      if (response.ok) {
        setSettingsActionStatus(`Thank you for rating us ${stars} stars!`)
        loadFeedbackAndCommunity()
        triggerPushNotification('Rating Submitted', `You successfully rated LEGATRIXON ${stars} stars!`)
      } else {
        const errorText = await response.text();
        setSettingsActionStatus(errorText || 'Failed to submit rating.');
      }
    } catch (err) {
      setSettingsActionStatus('Failed to submit rating.')
    }
  }

  const submitBugReport = async (e: React.FormEvent) => {
    e.preventDefault()
    if (!bugDescription.trim()) return
    setSettingsActionStatus('Submitting bug report...')
    try {
      let screenshotUrl = null
      if (bugScreenshotFile) {
        const fileExt = bugScreenshotFile.name.split('.').pop()
        const fileName = `${Math.random().toString(36).substring(2, 15)}_${Date.now()}.${fileExt}`
        const { error: uploadError } = await supabase.storage
          .from('bug-screenshots')
          .upload(fileName, bugScreenshotFile, {
            cacheControl: '3600',
            upsert: true,
          })
        if (uploadError) {
          console.error('Failed to upload screenshot to Supabase Storage:', uploadError)
          throw new Error(`Screenshot upload failed: ${uploadError.message}`)
        }
        const { data: publicUrlData } = supabase.storage
          .from('bug-screenshots')
          .getPublicUrl(fileName)
        screenshotUrl = publicUrlData?.publicUrl || null
      }

      const response = await fetch(`${settingsApiBase}/feedback`, {
        method: 'POST',
        headers: { 
          'Content-Type': 'application/json',
          Authorization: `Bearer ${apiToken}` 
        },
        body: JSON.stringify({
          type: 'bug',
          issueType: bugIssueType,
          module: bugModule,
          description: bugDescription,
          screenshotUrl,
        }),
      })
      if (response.ok) {
        setSettingsActionStatus('Bug report submitted successfully!')
        setBugDescription('')
        setBugScreenshotName('')
        setBugScreenshotFile(null)
        const form = e.target as HTMLFormElement;
        form.reset();
        loadFeedbackAndCommunity()
        triggerPushNotification('Bug Report Logged', 'Our developers are investigating your bug report.')
      } else {
        const errorText = await response.text()
        throw new Error(errorText || 'Server rejected the bug report.')
      }
    } catch (err: any) {
      setSettingsActionStatus(err.message || 'Failed to submit bug report.')
    }
  }

