  useEffect(() => {
    (window as any).logUserActivity = async (moduleName: string, actionType: string, metadata?: Record<string, any>) => {
      console.log(`[Activity Log] Module: ${moduleName}, Action: ${actionType}`, metadata);
      if (apiToken) {
        try {
          const response = await fetch('http://localhost:4000/api/v1/settings/activity', {
            method: 'POST',
            headers: {
              'Content-Type': 'application/json',
              'Authorization': `Bearer ${apiToken}`
            },
            body: JSON.stringify({
              module: moduleName,
              action: actionType,
              metadata: {
                ...metadata,
                timestamp: new Date().toISOString()
              }
            })
          });
          if (!response.ok) {
            throw new Error(`Activity API returned ${response.status}`);
          }
          return;
        } catch (err) {
          console.warn('Backend activity logging failed, trying direct Supabase insert:', err);
        }
      }

      if (clerkUser?.id) {
        try {
          const { error } = await supabase.from('user_activity_logs').insert([{
            user_id: clerkUser.id,
            module: moduleName,
            action: actionType,
            module_name: moduleName,
            action_type: actionType,
            session_id: metadata?.sessionId || metadata?.session_id || null,
            metadata: metadata || {},
            created_at: new Date().toISOString()
          }]);
          if (error) throw error;
        } catch (supabaseErr) {
          console.error('Direct Supabase activity logging failed:', supabaseErr);
        }
      }
    };
  }, [apiToken, clerkUser?.id]);

