  const runSettingsAction = async (
    path: string,
    successMessage: string,
    body: Record<string, unknown> = {},
    reload = true,
  ) => {
    setSettingsActionStatus('')
    try {
      const response = await fetch(`${settingsApiBase}${path}`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', ...(await getSettingsAuthHeaders()) },
        body: JSON.stringify(body),
      })
      if (!response.ok) throw new Error('Action could not be completed.')
      setSettingsActionStatus(successMessage)
      if (reload) loadSettingsDashboard()
      return true
    } catch (error: any) {
      setSettingsActionStatus(error.message || 'Action could not be completed.')
      return false
    }
  }

  const confirmSettingsDeletion = async (path: string, permanent = false) => {
    const confirmation = window.prompt(
      permanent
        ? 'This permanently removes your account and data. Type DELETE to continue.'
        : 'This deactivates your account. Type DELETE to continue.',
    )
    if (confirmation !== 'DELETE') return
    const completed = await runSettingsAction(
      path,
      permanent ? 'Account permanently deleted.' : 'Account deactivated.',
      { confirmation },
      !permanent,
    )
    if (completed && permanent) {
      await signOut()
      window.location.assign('/')
    }
  }

  const logoutAllDevices = async () => {
    if (!window.confirm('Log out every active Clerk session, including this device?')) return
    const completed = await runSettingsAction(
      '/danger/logout-all-devices',
      'All active sessions were revoked.',
      {},
      false,
    )
    if (completed) {
      await signOut()
      window.location.assign('/')
    }
  }

  const downloadSettingsExport = async (kind: string, format: string) => {
    try {
      const response = await fetch(`${settingsApiBase}/export/${kind}/${format}`, {
        headers: await getSettingsAuthHeaders(),
      })
      if (!response.ok) throw new Error('Export could not be generated.')
      const blob = await response.blob()
      const url = URL.createObjectURL(blob)
      const link = document.createElement('a')
      link.href = url
      link.download = `${kind}-export.${format}`
      link.click()
      URL.revokeObjectURL(url)
      setSettingsActionStatus(`${format.toUpperCase()} export generated.`)
    } catch (error: any) {
      setSettingsActionStatus(error.message || 'Export could not be generated.')
    }
  }

