  const handleExamIntelFileUpload = async (files: FileList | File[]) => {
    if (!files || !files.length) return;
    const fileArray = Array.from(files);
    
    setExamIntelUploadingName(fileArray.length === 1 ? fileArray[0].name : `${fileArray.length} files`);
    setExamIntelUploadProgress(15);
    
    try {
      const formData = new FormData();
      let uploadedDocs: any[] = [];
      if (fileArray.length === 1) {
        formData.append('file', fileArray[0]);
        const response = await fetch('http://localhost:4000/api/v1/notebook/upload', {
          method: 'POST',
          headers: { 'Authorization': `Bearer ${apiToken}` },
          body: formData
        });
        if (!response.ok) throw new Error('Upload failed');
        const doc = await response.json();
        uploadedDocs = [doc];
      } else {
        fileArray.forEach(file => formData.append('files', file));
        const response = await fetch('http://localhost:4000/api/v1/notebook/bulk-upload', {
          method: 'POST',
          headers: { 'Authorization': `Bearer ${apiToken}` },
          body: formData
        });
        if (!response.ok) throw new Error('Bulk upload failed');
        const data = await response.json();
        uploadedDocs = data.documents || [];
      }
      
      setExamIntelUploadProgress(50);
      
      // Update local doc list immediately so the UI shows the new processing documents
      await reloadDocsFromBackend();
      
      // Now poll each document until they are all finished (Indexed or Failed)
      const pendingDocIds = new Set(uploadedDocs.map(d => d.id));
      let attempts = 0;
      const maxAttempts = 240;
      
      const interval = setInterval(async () => {
        attempts++;
        if (pendingDocIds.size === 0 || attempts > maxAttempts) {
          clearInterval(interval);
          setExamIntelUploadProgress(100);
          await reloadDocsFromBackend();
          await fetchExamIntelStats();
          setTimeout(() => {
            setExamIntelUploadingName(null);
            setExamIntelUploadProgress(null);
          }, 1000);
          return;
        }
        
        // Check status of each pending document
        for (const docId of Array.from(pendingDocIds)) {
          try {
            const response = await fetch(`http://localhost:4000/api/v1/notebook/documents/${docId}`, {
              headers: { 'Authorization': `Bearer ${apiToken}` }
            });
            if (response.ok) {
              const doc = await response.json();
              if (doc.status === 'Indexed' || doc.status === 'Failed') {
                pendingDocIds.delete(docId);
              }
            }
          } catch (err) {
            console.error(`Error polling document ${docId}`, err);
          }
        }
        
        // Update simulated progress between 50% and 95%
        const finishedCount = uploadedDocs.length - pendingDocIds.size;
        const progressPercent = Math.min(95, 50 + Math.round((finishedCount / uploadedDocs.length) * 45));
        setExamIntelUploadProgress(progressPercent);
      }, 1500);

    } catch (err: any) {
      console.error(err);
      alert(err.message || 'File ingestion failed.');
      setExamIntelUploadingName(null);
      setExamIntelUploadProgress(null);
    }
  };

  const handleExamIntelUrlSubmit = async () => {
    if (!examIntelUrlValue.trim()) return;
    setIsExamIntelUrlSubmitting(true);
    try {
      const response = await fetch('http://localhost:4000/api/v1/notebook/url-ingest', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${apiToken}`
        },
        body: JSON.stringify({
          url: examIntelUrlValue.trim(),
          name: examIntelUrlName.trim() || undefined
        })
      });
      const data = await response.json();
      if (!response.ok) throw new Error(data.message || 'URL ingestion failed');
      
      // Since URL ingest returns the doc directly, poll it in background as well
      if (data && data.id) {
        setExamIntelUploadingName(data.name);
        setExamIntelUploadProgress(50);
        
        const interval = setInterval(async () => {
          try {
            const pollResponse = await fetch(`http://localhost:4000/api/v1/notebook/documents/${data.id}`, {
              headers: { 'Authorization': `Bearer ${apiToken}` }
            });
            if (pollResponse.ok) {
              const doc = await pollResponse.json();
              if (doc.status === 'Indexed' || doc.status === 'Failed') {
                clearInterval(interval);
                setExamIntelUploadProgress(100);
                await reloadDocsFromBackend();
                await fetchExamIntelStats();
                setTimeout(() => {
                  setExamIntelUploadingName(null);
                  setExamIntelUploadProgress(null);
                }, 1000);
              }
            }
          } catch (err) {
            clearInterval(interval);
            setExamIntelUploadingName(null);
            setExamIntelUploadProgress(null);
          }
        }, 1500);
      } else {
        await reloadDocsFromBackend();
        await fetchExamIntelStats();
      }
      
      setExamIntelUrlValue('');
      setExamIntelUrlName('');
      setShowExamIntelUrlModal(false);
    } catch (err: any) {
      console.error(err);
      alert(err.message || 'Failed to crawl URL.');
    } finally {
      setIsExamIntelUrlSubmitting(false);
    }
  };

  const handleExamIntelPasteSubmit = async () => {
    if (!examIntelPasteContent.trim()) return;
    setIsExamIntelPasteSubmitting(true);
    try {
      const title = examIntelPasteTitle.trim() || 'Pasted Notes';
      const file = new File([examIntelPasteContent], `${title}.txt`, { type: 'text/plain' });
      await handleExamIntelFileUpload([file]);
      
      setExamIntelPasteTitle('');
      setExamIntelPasteContent('');
      setShowExamIntelPasteModal(false);
    } catch (err: any) {
      console.error(err);
      alert('Failed to ingest pasted notes.');
    } finally {
      setIsExamIntelPasteSubmitting(false);
    }
  };

  const handleExamIntelGenerateTest = async (customPrompt?: string) => {
    const activePrompt = (customPrompt || examIntelTestPrompt || 'Generate a full semester mock test from my uploaded study library.').trim();
    if (lexDocs.length === 0) {
      setExamIntelTestError('Please upload study material first.');
      return;
    }

    setIsExamIntelTestGenerating(true);
    setExamIntelTestError(null);
    setExamIntelGeneratedTest(null);
    setExamIntelAnswers({});
    setExamIntelEvaluatedResult(null);
    setShowExamIntelTestPage(true);

    try {
      const response = await fetch('http://localhost:4000/api/v1/exam/study-library/generate-test', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${apiToken}`
        },
        body: JSON.stringify({
          prompt: activePrompt,
          sourceScope: 'entire-study-library',
          libraryOnly: true,
          docIds: lexDocs.map((doc) => doc.id),
          settings: {
            mode: 'personal-ai-exam-preparation-workspace',
            command: activePrompt,
            inferExamDesignFromUploadedMaterial: true,
            strictGrounding: true,
            noExternalKnowledge: true,
            noInternetKnowledge: true,
            noModelAssumptions: true,
            priorityOrder: [
              'Teacher Notes',
              'Previous Year Papers',
              'Exam Pattern',
              'Syllabus',
              'Class Notes',
              'PPT Slides',
              'Reference Material'
            ],
            analyzeSources: [
              'Teacher Notes',
              'Class Notes',
              'PPTs',
              'Books',
              'Previous Year Papers',
              'Sample Papers',
              'Exam Pattern',
              'Syllabus'
            ],
            requiredQuestionGrounding: {
              sourceDocument: true,
              sourcePage: true,
              sourceChunk: true
            },
            insufficientMaterialMessage: 'Insufficient study material found for this topic.'
          }
        })
      });
      const data = await response.json();
      if (!response.ok || data.success === false) {
        throw new Error(data.message || 'Failed to generate test');
      }
      setExamIntelGeneratedTest(data);
    } catch (err: any) {
      console.error(err);
      setExamIntelTestError(err.message || 'Could not generate test. Please try uploading more files.');
    } finally {
      setIsExamIntelTestGenerating(false);
    }
  };

  const downloadMockTestExport = async (format: 'pdf' | 'docx') => {
    if (!examIntelGeneratedTest || !examIntelGeneratedTest.id) return;
    try {
      const response = await fetch(`http://localhost:4000/api/v1/learning-workspace/mock-tests/${examIntelGeneratedTest.id}/export/${format}`, {
        headers: {
          'Authorization': `Bearer ${apiToken}`
        }
      });
      if (!response.ok) throw new Error('Export could not be generated.');
      const blob = await response.blob();
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = `${examIntelGeneratedTest.subject.replace(/\s+/g, '_')}_MockTest.${format}`;
      link.click();
      URL.revokeObjectURL(url);
    } catch (error: any) {
      alert(error.message || 'Export could not be generated.');
    }
  };

  const handleExamIntelEvaluate = async () => {
    if (!examIntelGeneratedTest) return;
    setIsExamIntelEvaluating(true);
    try {
      const response = await fetch('http://localhost:4000/api/v1/exam/mock-paper/evaluate', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${apiToken}`
        },
        body: JSON.stringify({
          subject: 'Study Library Mock Test',
          paperType: 'Mock Test',
          questions: examIntelGeneratedTest.questions.map((q: any) => ({
            id: q.id,
            question: q.question,
            marks: q.marks,
            topic: q.grounding?.documentName || 'General'
          })),
          answers: examIntelAnswers
        })
      });
      const data = await response.json();
      setExamIntelEvaluatedResult(data);
      await fetchExamIntelStats();
      await fetchExamIntelInsights();
    } catch (err) {
      console.error(err);
      alert('Failed to evaluate mock test. Please try again.');
    } finally {
      setIsExamIntelEvaluating(false);
    }
  };

  const [selectedLexDocId, setSelectedLexDocId] = useState<string | null>(null)
  const [lexSearchQuery, setLexSearchQuery] = useState('')
  const [isLexDragging, setIsLexDragging] = useState(false)
  const [lexUploadProgress, setLexUploadProgress] = useState<number | null>(null)
  const [lexUploadingName, setLexUploadingName] = useState<string | null>(null)
  
  // LexNotebook AI Chat State
  const [lexWorkspaceMode, setLexWorkspaceMode] = useState<'ingest' | 'chat' | 'search' | 'extraction' | 'graph' | 'metadata' | 'citations'>('ingest')
  const [lexChatMessages, setLexChatMessages] = useState<Record<string, Array<{ role: 'user' | 'assistant'; text: string; citations?: Array<{ id: number; name: string; pageNumber: number; chunkIndex?: number; text: string; confidenceScore?: number }>; confidence?: number }>>>({})
  const [lexChatInput, setLexChatInput] = useState('')
  const [isLexChatTyping, setIsLexChatTyping] = useState(false)
  const [activeCitationId, setActiveCitationId] = useState<number | null>(null)
  const [lexSemanticQuery, setLexSemanticQuery] = useState('')
  const [lexSearchMode, setLexSearchMode] = useState<'keyword' | 'vector' | 'hybrid'>('hybrid')
  const [lexSearchResults, setLexSearchResults] = useState<any | null>(null)
  const [isLexSearching, setIsLexSearching] = useState(false)
  const [lexGraph, setLexGraph] = useState<{ nodes: any[]; edges: any[] } | null>(null)
  const [isLexGraphLoading, setIsLexGraphLoading] = useState(false)
  const [isLexExtracting, setIsLexExtracting] = useState(false)

  const parseApiError = async (response: Response, fallback: string) => {
    const raw = await response.text();
    if (!raw) return fallback;
    try {
      const parsed = JSON.parse(raw);
      if (response.status === 402 && parsed.code === 'AI_CREDITS_EXHAUSTED') {
        setAiLimitReached({
          moduleKey: parsed.moduleKey || 'ai',
          moduleLabel: parsed.moduleLabel || 'AI',
          message: parsed.message || 'You have used your free AI credits.',
        })
      }
      return parsed.message || parsed.error || raw;
    } catch {
      return raw;
    }
  };

  const readLocalStudyForge = (docId: string) => {
    try {
      const raw = window.localStorage.getItem(`study-forge:${docId}`)
      return raw ? JSON.parse(raw) : null
    } catch {
      return null
    }
  }

  const saveLocalStudyForge = (docId: string, studyForge: any) => {
    try {
      window.localStorage.setItem(`study-forge:${docId}`, JSON.stringify(studyForge))
    } catch {}
  }



  const mapLexDoc = (d: any): LexDocument => ({
    id: d.id,
    name: d.name,
    type: d.type,
    size: d.size,
    uploadedAt: new Date(d.uploadedAt).toISOString().replace('T', ' ').substring(0, 16),
    status: d.status,
    previewContent: d.previewContent || '',
    wordCount: d.wordCount || 0,
    pages: d.pages || 0,
    documentType: d.documentType || d.legalMetadata?.documentType || d.type?.toUpperCase(),
    errorMessage: d.errorMessage || null,
    tags: d.tags || [d.type.toUpperCase()],
    clausesCount: d.clausesCount || 0,
    legalMetadata: d.legalMetadata || null,
    studyForge: d.studyForge || readLocalStudyForge(d.id) || null
  });

  const isLexDocIndexed = (doc?: Pick<LexDocument, 'status'> | null) =>
    doc?.status === 'Indexed' || doc?.status === 'Ready';

  const getDocChatHistory = (docId: string) => {
    if (!lexChatMessages[docId]) {
      const doc = lexDocs.find(d => d.id === docId);
      const docName = doc ? doc.name : 'your document';
      return [
        {
          role: 'assistant' as const,
          text: `Hi! I'm LexNotebook AI. I am fully grounded in "${docName}". Ask me anything about this document, and I will cite exact pages and sources from it!`,
        }
      ];
    }
    return lexChatMessages[docId];
  };

  // Fetch real document library from PostgreSQL backend
  useEffect(() => {
    const fetchDocuments = async () => {
      if (!apiToken) return;
      try {
        const response = await fetch('http://localhost:4000/api/v1/notebook/documents', {
          headers: { 'Authorization': `Bearer ${apiToken}` }
        });
        if (response.ok) {
          const docs = await response.json();
          if (docs && Array.isArray(docs)) {
            const mapped = docs.map(mapLexDoc);
            if (mapped.length > 0) {
              setLexDocs(mapped);
              setSelectedLexDocId(mapped[0].id);
            } else {
              setLexDocs([]);
              setSelectedLexDocId(null);
            }
          }
        }
      } catch (err) {
        console.error('[LexNotebook AI] Backend offline or unreachable.', err);
      }
    };
    fetchDocuments();
  }, [apiToken]);

  // Hide welcome message when user starts typing or chat grows
  // (moved below to after mentorMessages is defined)

  // Fetch document chunks dynamically from backend when selected
  useEffect(() => {
    if (!selectedLexDocId || selectedLexDocId === 'all') return;
    const fetchChunks = async () => {
      try {
        const response = await fetch(`http://localhost:4000/api/v1/notebook/documents/${selectedLexDocId}/chunks`, {
          headers: { 'Authorization': `Bearer ${apiToken}` }
        });
        if (response.ok) {
          const chunks = await response.json();
          if (chunks && Array.isArray(chunks)) {
            const combinedText = chunks.map((c: any) => c.text).join('\n\n');
            setLexDocs(prev => prev.map(d => d.id === selectedLexDocId ? { ...d, previewContent: combinedText, chunks } : d));
          }
        }
      } catch (err) {
        console.warn(`[LexNotebook AI] Failed to fetch chunks for document ${selectedLexDocId}`, err);
      }
    };
    fetchChunks();
  }, [selectedLexDocId]);

  useEffect(() => {
    if (!selectedLexDocId || selectedLexDocId === 'all') return;
    const fetchChatHistory = async () => {
      try {
        const response = await fetch(`http://localhost:4000/api/v1/notebook/documents/${selectedLexDocId}/chat-history`, {
          headers: { 'Authorization': `Bearer ${apiToken}` }
        });
        if (!response.ok) return;
        const history = await response.json();
        if (Array.isArray(history) && history.length > 0) {
          setLexChatMessages(prev => ({
            ...prev,
            [selectedLexDocId]: history.map((msg: any) => ({
              role: msg.role,
              text: msg.text,
              citations: msg.citations || undefined,
              confidence: msg.confidence ?? undefined,
            }))
          }));
        }
      } catch (err) {
        console.warn(`[LexNotebook AI] Failed to fetch chat history for document ${selectedLexDocId}`, err);
      }
    };
    fetchChatHistory();
  }, [selectedLexDocId]);

  useEffect(() => {
    if (lexWorkspaceMode === 'graph') {
      loadLexGraph();
    }
  }, [lexWorkspaceMode, selectedLexDocId]);

  // Handles Real Ingestion with simulated visual progress matching PDF statuses (Uploading -> Processing -> Indexed/Failed)
  const handleDocumentIngestion = async (file: File, documentType?: string) => {
    setLexUploadingName(file.name);
    setLexUploadProgress(0);

    // 1. Simulate Upload Phase in UI
    let progressVal = 0;
    const uploadTimer = setInterval(() => {
      progressVal += 15;
      if (progressVal >= 100) {
        clearInterval(uploadTimer);
        setLexUploadProgress(null);
        // Start real processing request
        proceedWithIngestionBackend(file, documentType);
      } else {
        setLexUploadProgress(progressVal);
      }
    }, 100);
  };

  const proceedWithIngestionBackend = async (file: File, documentType?: string) => {
    try {
      const formData = new FormData();
      formData.append('file', file);
      if (documentType) {
        formData.append('documentType', documentType);
      }

      // Post real multipart form data to NestJS API
      const response = await fetch('http://localhost:4000/api/v1/notebook/upload', {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${apiToken}`
        },
        body: formData
      });

      if (!response.ok) {
        throw new Error(await parseApiError(response, 'Backend upload call failed.'));
      }

      const doc = await response.json();
      
      // Update UI doc list immediately in Processing state
      const initialDoc = mapLexDoc(doc);
      setLexDocs(prev => [initialDoc, ...prev]);
      setSelectedLexDocId(initialDoc.id);

      (window as any).logUserActivity?.('LexMentor AI', 'Uploaded Document', { fileName: file.name, fileSize: file.size });

      // 2. Poll Document processing status (Processing -> Indexed / Failed)
      pollDocumentStatus(doc.id);
    } catch (err) {
      const errorText = err instanceof Error ? err.message : 'Upload failed.';
      alert(`Upload failed: ${errorText}`);
      setLexUploadingName(null);
      setLexUploadProgress(null);
    }
  };

  const pollDocumentStatus = (docId: string) => {
    let attempts = 0;
    const maxAttempts = 240;
    const interval = setInterval(async () => {
      attempts++;
      try {
        const response = await fetch(`http://localhost:4000/api/v1/notebook/documents/${docId}`, {
          headers: { 'Authorization': `Bearer ${apiToken}` }
        });
        
        if (response.ok) {
          const doc = await response.json();
          const mappedDoc = mapLexDoc(doc);
          setLexDocs(prev => prev.map(d => d.id === doc.id ? { ...d, ...mappedDoc } : d));

          if (isLexDocIndexed(doc)) {
            clearInterval(interval);
            setSelectedLexDocId(doc.id);
            setLexUploadingName(null);
            
            // Reload whole document list to ensure proper ordering
            reloadDocsFromBackend();
            setStudyForgeStatusText('Document indexed. Choose a Study Forge tool when you are ready.');
          } else if (doc.status === 'Failed') {
            clearInterval(interval);
            setLexUploadingName(null);
            const reason = doc.errorMessage || 'Unknown processing failure';
            alert(`Ingestion failed for document ${doc.name}: ${reason}`);
          } else if (attempts > maxAttempts) {
            clearInterval(interval);
            setLexUploadingName(null);
            setLexDocs(prev => prev.map(d => d.id === doc.id ? {
              ...d,
              status: doc.status,
              errorMessage: 'Still processing on the backend. Refresh the library or open this document again to continue polling.'
            } : d));
          }
        }
      } catch (err) {
        clearInterval(interval);
        setLexUploadingName(null);
      }
    }, 1500);
  };

  const reloadDocsFromBackend = async () => {
    try {
      const response = await fetch('http://localhost:4000/api/v1/notebook/documents', {
        headers: { 'Authorization': `Bearer ${apiToken}` }
      });
      if (response.ok) {
        const docs = await response.json();
        if (docs && Array.isArray(docs)) {
          const mapped = docs.map(mapLexDoc);
          setLexDocs(mapped);
          if (!selectedLexDocId && mapped.length > 0) {
            setSelectedLexDocId(mapped[0].id);
          }
        }
      }
    } catch (err) {}
  };

  // Handle Drag Events
  const handleLexDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    setIsLexDragging(true);
  };

  const handleLexDragLeave = (e: React.DragEvent) => {
    e.preventDefault();
    setIsLexDragging(false);
  };

  const handleLexDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsLexDragging(false);
    
    if (e.dataTransfer.files && e.dataTransfer.files.length > 0) {
      const file = e.dataTransfer.files[0];
      // Validate support
      const name = file.name;
      const ext = name.split('.').pop()?.toLowerCase() || '';
      if (['pdf', 'docx', 'txt'].includes(ext)) {
        handleDocumentIngestion(file);
      } else {
        alert('Format not supported! Please drop PDF, DOCX, or TXT files.');
      }
    }
  };

  // Handle File Input Change
  const handleLexFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      const file = e.target.files[0];
      handleDocumentIngestion(file);
    }
  };

  // Delete Document from real backend database
  const deleteLexDoc = async (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    
    // Remove locally immediately for immediate UI response
    setLexDocs(prev => prev.filter(doc => doc.id !== id));
    if (selectedLexDocId === id) {
      setSelectedLexDocId(null);
    }

    try {
      await fetch(`http://localhost:4000/api/v1/notebook/documents/${id}`, {
        method: 'DELETE',
        headers: { 'Authorization': `Bearer ${apiToken}` }
      });
    } catch (err) {
      console.warn('[LexNotebook AI] Failed to delete document from real database.', err);
    }
  };

  const reprocessLexDoc = async (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    setLexDocs(prev => prev.map(doc => doc.id === id ? { ...doc, status: 'Processing', errorMessage: null } : doc));
    try {
      const response = await fetch(`http://localhost:4000/api/v1/notebook/documents/${id}/reprocess`, {
        method: 'POST',
        headers: { 'Authorization': `Bearer ${apiToken}` }
      });
      if (!response.ok) {
        throw new Error(await response.text());
      }
      pollDocumentStatus(id);
    } catch (err) {
      const errorText = err instanceof Error ? err.message : 'Reprocess failed.';
      setLexDocs(prev => prev.map(doc => doc.id === id ? { ...doc, status: 'Failed', errorMessage: errorText } : doc));
    }
  };

  const openLexDocFile = async (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    try {
      const response = await fetch(`http://localhost:4000/api/v1/notebook/documents/${id}/file`, {
        headers: { 'Authorization': `Bearer ${apiToken}` }
      });
      if (!response.ok) {
        throw new Error(await parseApiError(response, 'Original file could not be opened.'));
      }
      const blob = await response.blob();
      const url = URL.createObjectURL(blob);
      window.open(url, '_blank', 'noopener,noreferrer');
      setTimeout(() => URL.revokeObjectURL(url), 60_000);
    } catch (err) {
      alert(err instanceof Error ? err.message : 'Original file could not be opened.');
    }
  };

  const runLexSearch = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!lexSemanticQuery.trim()) return;
    setIsLexSearching(true);
    try {
      const params = new URLSearchParams({
        q: lexSemanticQuery,
        mode: lexSearchMode,
      });
      if (selectedLexDocId) params.set('documentId', selectedLexDocId);
      const response = await fetch(`http://localhost:4000/api/v1/notebook/search?${params.toString()}`, {
        headers: { 'Authorization': `Bearer ${apiToken}` }
      });
      if (!response.ok) throw new Error(await response.text());
      setLexSearchResults(await response.json());
    } catch (err) {
      setLexSearchResults({ error: err instanceof Error ? err.message : 'Search failed.' });
    } finally {
      setIsLexSearching(false);
    }
  };

  const loadLexGraph = async () => {
    setIsLexGraphLoading(true);
    try {
      const params = new URLSearchParams();
      if (selectedLexDocId) params.set('documentId', selectedLexDocId);
      const graphUrl = `http://localhost:4000/api/v1/notebook/graph${params.toString() ? `?${params.toString()}` : ''}`;
      const response = await fetch(graphUrl, {
        headers: { 'Authorization': `Bearer ${apiToken}` }
      });
      if (!response.ok) throw new Error(await response.text());
      setLexGraph(await response.json());
    } catch (err) {
      setLexGraph({ nodes: [], edges: [{ error: err instanceof Error ? err.message : 'Graph failed.' }] });
    } finally {
      setIsLexGraphLoading(false);
    }
  };

  const runLexExtraction = async (docId: string) => {
    setIsLexExtracting(true);
    try {
      const response = await fetch(`http://localhost:4000/api/v1/notebook/documents/${docId}/extraction`, {
        method: 'POST',
        headers: { 'Authorization': `Bearer ${apiToken}` }
      });
      if (!response.ok) throw new Error(await parseApiError(response, 'Legal extraction failed.'));
      const updatedDoc = await response.json();
      const mappedDoc = mapLexDoc(updatedDoc);
      setLexDocs(prev => prev.map(doc => doc.id === docId ? { ...doc, ...mappedDoc } : doc));
      setSelectedLexDocId(docId);
      await loadLexGraph();
    } catch (err) {
      const errorText = err instanceof Error ? err.message : 'Legal extraction failed.';
      setLexDocs(prev => prev.map(doc => doc.id === docId ? { ...doc, errorMessage: errorText } : doc));
      alert(`Legal extraction failed: ${errorText}`);
    } finally {
      setIsLexExtracting(false);
    }
  };

  const sendLexChatMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedLexDocId || !lexChatInput.trim() || isLexChatTyping) return;

    const docId = selectedLexDocId;
    const userQuery = lexChatInput;
    setLexChatInput('');
    setIsLexChatTyping(true);
    setActiveCitationId(null); // Reset highlighted citation

    (window as any).logUserActivity?.('LexMentor AI', 'Asked Question', { query: userQuery, documentId: docId });

    // Get current history for this document
    const currentHistory = getDocChatHistory(docId);
    
    // Add user message
    const updatedHistory = [
      ...currentHistory,
      { role: 'user' as const, text: userQuery }
    ];
    setLexChatMessages(prev => ({
      ...prev,
      [docId]: updatedHistory
    }));

    // Add empty assistant response to stream into
    const assistantMsgIndex = updatedHistory.length;
    const nextHistory = [
      ...updatedHistory,
      { role: 'assistant' as const, text: '' }
    ];
    setLexChatMessages(prev => ({
      ...prev,
      [docId]: nextHistory
    }));

    try {
      // Try calling actual NestJS backend
      const response = await fetch('http://localhost:4000/api/v1/notebook/chat', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${apiToken}`
        },
        body: JSON.stringify({
          documentId: docId,
          message: userQuery,
          history: currentHistory.map(m => ({ role: m.role, text: m.text }))
        })
      });

      if (!response.ok) {
        throw new Error('SSE stream endpoint returned non-ok status');
      }

      const reader = response.body?.getReader();
      if (!reader) {
        throw new Error('Response body is not readable');
      }

      const decoder = new TextDecoder('utf-8');
      let assistantText = '';
      let citations: any[] = [];
      let buffer = '';

      while (true) {
        const { done, value } = await reader.read();
        if (done) break;

        buffer += decoder.decode(value, { stream: true });
        
        // SSE messages are delimited by double newlines \n\n
        const parts = buffer.split('\n\n');
        buffer = parts.pop() || ''; // Keep the last partial line in buffer

        for (const part of parts) {
          if (!part.startsWith('data: ')) continue;
          const jsonStr = part.substring(6).trim();
          if (!jsonStr) continue;

          try {
            const data = JSON.parse(jsonStr);
            if (data.token) {
              assistantText += data.token;
              setLexChatMessages(prev => {
                const history = [...(prev[docId] || [])];
                if (history[assistantMsgIndex]) {
                  history[assistantMsgIndex] = {
                    ...history[assistantMsgIndex],
                    text: assistantText
                  };
                }
                return { ...prev, [docId]: history };
              });
            } else if (data.citations) {
              citations = data.citations;
              setLexChatMessages(prev => {
                const history = [...(prev[docId] || [])];
                if (history[assistantMsgIndex]) {
                  history[assistantMsgIndex] = {
                    ...history[assistantMsgIndex],
                    citations: citations,
                    confidence: data.confidence
                  };
                }
                return { ...prev, [docId]: history };
              });
            } else if (data.error) {
              assistantText = data.error;
              setLexChatMessages(prev => {
                const history = [...(prev[docId] || [])];
                if (history[assistantMsgIndex]) {
                  history[assistantMsgIndex] = {
                    ...history[assistantMsgIndex],
                    text: assistantText,
                    citations,
                    confidence: data.confidence
                  };
                }
                return { ...prev, [docId]: history };
              });
            }
          } catch (e) {
            console.error('Error parsing SSE data:', e);
          }
        }
      }
      setIsLexChatTyping(false);
    } catch (err) {
      const errorText = err instanceof Error ? err.message : 'Grounded chat failed.';
      setLexChatMessages(prev => {
        const history = [...(prev[docId] || [])];
        if (history[assistantMsgIndex]) {
          history[assistantMsgIndex] = {
            ...history[assistantMsgIndex],
            text: `Backend grounded chat failed: ${errorText}`
          };
        }
        return { ...prev, [docId]: history };
      });
      setIsLexChatTyping(false);
    }
  };

