  const handleGenerateResearch = async () => {
    const topic = researchTopic.trim()
    const selectedModuleFiles = sessionFiles.filter((file) => file.docCategory === uploadCategory)
    if (selectedModuleFiles.length === 0) {
      setResearchStatus(`Upload or select a ${uploadCategory} document first`)
      setResearchProgressStep('')
      setIsResearchLoading(false)
      return
    }

    const workflow = DOCUMENT_WORKFLOWS[uploadCategory]
    if (workflow) {
      const defAction = workflow.actions.find(a => a.id === workflow.defaultAction)
      if (defAction) {
        triggerDocAction(uploadCategory, defAction.id, defAction.label)
        setShowDocumentWorkspace(true)
      }
    }

    if (uploadCategory === 'Moot Proposition') {
      try {
        setIsResearchLoading(true)
        setResearchStatus('Extracting proposition blueprint through backend memorial workflow...')
        await runMemorialWorkflowFromCurrentFile('both')
        setResearchStatus('Proposition blueprint extracted. Petitioner/respondent memorial exports are ready.')
      } catch (error: any) {
        console.error('Blueprint extraction failed', error)
        setResearchStatus(`Blueprint extraction failed: ${error?.message || error}`)
      } finally {
        setIsResearchLoading(false)
        setResearchProgressStep('')
      }
      return
    }

    if (!topic && uploadCategory !== 'Memorial') {
      setResearchStatus('Enter a topic first')
      return
    }

    setIsResearchLoading(true)
    const btnConfig = PRIMARY_ACTION_BUTTONS[uploadCategory] || PRIMARY_ACTION_BUTTONS.Memorial
    const detectedType = selectedModuleFiles[0]?.detectedCategory || selectedModuleFiles[0]?.docCategory || uploadCategory
    const pipelineName = getLegalResearchPipelineName(uploadCategory)
    const effectiveResearchMode = getResearchModeForWorkspace(uploadCategory) || 'Academic'
    const executionProfile = getResearchExecutionProfile(effectiveResearchMode, researchDepth || 'standard', uploadCategory)
    setResearchStatus(`Selected Workspace: ${uploadCategory} | Detected Type: ${detectedType} | Pipeline: ${pipelineName}`)
    setResearchProgressStep(`Selected Workspace: ${uploadCategory} | Detected Type: ${detectedType} | Pipeline: ${pipelineName}`)

    let step = 0
    const steps = btnConfig.steps
    const timer = setInterval(() => {
      if (step < steps.length) {
        setResearchProgressStep(`${steps[step]} (${pipelineName})`)
        step++
      }
    }, 2800)

    try {
      const endpoint = uploadCategory === 'Judgment'
        ? '/judgment-intelligence'
        : uploadCategory === 'Legal Brief'
          ? '/legal-brief'
          : uploadCategory === 'Bare Act'
            ? '/bare-act'
            : '/generate'
      const payload = await requestResearchApi<any>(endpoint, {
        method: 'POST',
        body: JSON.stringify({
          queryId: currentQueryId,
          topic,
          researchMode: effectiveResearchMode,
          sources: selectedSources.length > 0 ? selectedSources : [
            'constitution',
            'acts',
            'judgments',
            'research_papers',
            'user_documents',
            'law_commission_reports'
          ],
          provider: researchModel || 'deepseek',
          depth: researchDepth || 'standard',
          tokenBudget: executionProfile.maxOutputTokens,
          maxOutputTokens: executionProfile.maxOutputTokens,
          retrievalLimit: executionProfile.retrievalLimit,
          chunkTokenLimit: executionProfile.chunkTokenLimit,
          reasoningEffort: executionProfile.reasoningEffort,
          temperature: executionProfile.temperature,
          outputLens: executionProfile.outputLens,
          compression: executionProfile.compression,
          cacheStrategy: executionProfile.cacheStrategy,
          tokenPolicy: executionProfile.tokenPolicy,
          executionProfile,
          selectedWorkspace: uploadCategory,
          detectedType,
          pipeline: pipelineName,
        }),
      });
      clearInterval(timer);
      hydrateResearchReport(payload);
      if (uploadCategory === 'Judgment') {
        await fetchJudgmentHistory('')
        setJudgmentSearch('')
        setShowDocumentWorkspace(false)
      } else if (uploadCategory === 'Legal Brief') {
        setShowDocumentWorkspace(true)
      } else if (uploadCategory === 'Bare Act') {
        setShowDocumentWorkspace(true)
      }
      setResearchStatus(uploadCategory === 'Judgment' ? 'Judgment intelligence generated and saved' : uploadCategory === 'Legal Brief' ? 'Legal brief generated in case brief format' : uploadCategory === 'Bare Act' ? 'Bare Act statutory analysis generated' : uploadCategory === 'Memorial' ? 'Memorial report generated successfully' : uploadCategory === 'Research Paper' ? 'Research Paper report generated successfully' : 'Report generated successfully');
      (window as any).logUserActivity?.('Legal Research Command Center', uploadCategory === 'Judgment' ? 'Generated Judgment Intelligence' : uploadCategory === 'Legal Brief' ? 'Generated Legal Brief' : uploadCategory === 'Bare Act' ? 'Generated Bare Act Analysis' : uploadCategory === 'Memorial' ? 'Generated Memorial Report' : uploadCategory === 'Research Paper' ? 'Generated Research Paper Report' : 'Generated Research Report', { topic, mode: effectiveResearchMode, selectedWorkspace: uploadCategory, detectedType, pipeline: pipelineName });
    } catch (error) {
      clearInterval(timer);
      setResearchStatus('Failed to compile report. Ensure server is online.');
    } finally {
      setIsResearchLoading(false);
      setResearchProgressStep('');
    }
  }
 
