  const getSectionText = (reportSummary: string | undefined, sectionKey: string): string => {
    const summaryStr = reportSummary || ''
    if (!summaryStr) return ''
    
    const headers = [
      { name: 'Cover Page', index: 1 },
      { name: 'Abstract', index: 2 },
      { name: 'Table of Contents', index: 3 },
      { name: 'Introduction', index: 4 },
      { name: 'Research Questions', index: 5 },
      { name: 'Objectives of Study', index: 6 },
      { name: 'Research Methodology', index: 7 },
      { name: 'Constitutional Framework', index: 8 },
      { name: 'Relevant Statutes', index: 9 },
      { name: 'Historical Evolution Timeline', index: 10 },
      { name: 'Landmark Cases', index: 11 },
      { name: 'Ratio Decidendi Matrix', index: 12 },
      { name: 'Comparative Jurisprudence', index: 13 },
      { name: 'Conflicting Judicial Views', index: 14 },
      { name: 'Academic Commentary', index: 15 },
      { name: 'Practical Implications', index: 16 },
      { name: 'Emerging Challenges', index: 17 },
      { name: 'Findings', index: 18 },
      { name: 'Recommendations', index: 19 },
      { name: 'Conclusion', index: 20 },
      { name: 'Bibliography', index: 21 },
      { name: 'Citation Sheet', index: 22 }
    ]

    const extractBetween = (startIdx: number, endIdx?: number) => {
      const startHeader = headers.find(h => h.index === startIdx)?.name
      const endHeader = endIdx ? headers.find(h => h.index === endIdx)?.name : null
      
      if (!startHeader) return ''
      
      const escapedStart = startHeader.replace(/[-\/\\^$*+?.()|[\]{}]/g, '\\$&')
      const escapedEnd = endHeader ? endHeader.replace(/[-\/\\^$*+?.()|[\]{}]/g, '\\$&') : null
      
      const regexStr = escapedEnd 
        ? `##?\\s*\\d*\\.?\\s*${escapedStart}\\b([\\s\\S]*?)(?=##?\\s*\\d*\\.?\\s*${escapedEnd}\\b)`
        : `##?\\s*\\d*\\.?\\s*${escapedStart}\\b([\\s\\S]*?)$`
        
      const regex = new RegExp(regexStr, 'i')
      const match = summaryStr.match(regex)
      if (match) {
        return `# ${startIdx}. ${startHeader}\n\n${match[1].trim()}`
      }
      return ''
    }

    switch(sectionKey) {
      case 'overview': {
        const text = [
          extractBetween(1, 2),
          extractBetween(2, 3),
          extractBetween(3, 4),
          extractBetween(4, 5),
          extractBetween(5, 6),
          extractBetween(6, 7),
          extractBetween(7, 8)
        ].filter(Boolean).join('\n\n')
        return text || summaryStr
      }
      case 'constitutional-provisions':
        return extractBetween(8, 9)
      case 'relevant-statutes':
        return extractBetween(9, 10)
      case 'landmark-cases':
        return [extractBetween(11, 12), extractBetween(12, 13)].filter(Boolean).join('\n\n')
      case 'timeline':
        return extractBetween(10, 11)
      case 'conflicting-views':
        return [
          extractBetween(13, 14),
          extractBetween(14, 15),
          extractBetween(15, 16),
          extractBetween(16, 17),
          extractBetween(17, 18),
          extractBetween(18, 19),
          extractBetween(19, 20),
          extractBetween(20, 21)
        ].filter(Boolean).join('\n\n')
      case 'citations':
        return [extractBetween(21, 22), extractBetween(22)].filter(Boolean).join('\n\n')
      default:
        return ''
    }
  }

  const renderTextWithInlineFormatting = (text: string) => {
    if (!text) return '';
    const parts = text.split(/(\*\*.*?\*\*|\*.*?\*|`.*?`|_.*?_)/g);
    return parts.map((part, index) => {
      if (part.startsWith('**') && part.endsWith('**')) {
        return <strong key={index} style={{ color: 'var(--gold)', fontWeight: '700' }}>{part.slice(2, -2)}</strong>;
      }
      if (part.startsWith('_') && part.endsWith('_')) {
        return <em key={index}>{part.slice(1, -1)}</em>;
      }
      if (part.startsWith('*') && part.endsWith('*')) {
        return <em key={index}>{part.slice(1, -1)}</em>;
      }
      if (part.startsWith('`') && part.endsWith('`')) {
        return <code key={index} className="report-code" style={{ background: 'var(--gold-soft)', padding: '2px 6px', borderRadius: '4px', fontSize: '0.78rem', fontFamily: 'monospace' }}>{part.slice(1, -1)}</code>;
      }
      return part;
    });
  };

  const formatMarkdown = (text: string) => {
    if (!text) return <p className="text-soft">No content available for this section.</p>
    
    return text.split('\n').map((line, idx) => {
      const trimmed = line.trim()
      if (trimmed.startsWith('# ')) {
        return <h3 key={idx} className="report-h1" style={{ fontSize: '1.35rem', color: 'var(--gold)', margin: '20px 0 10px 0', fontWeight: '700', borderBottom: '1px solid var(--line)', paddingBottom: '6px' }}>{renderTextWithInlineFormatting(trimmed.substring(2))}</h3>
      }
      if (trimmed.startsWith('## ')) {
        return <h4 key={idx} className="report-h2" style={{ fontSize: '1.15rem', color: 'var(--navy)', margin: '14px 0 8px 0', fontWeight: '600' }}>{renderTextWithInlineFormatting(trimmed.substring(3))}</h4>
      }
      if (trimmed.startsWith('* ') || trimmed.startsWith('- ')) {
        return <li key={idx} className="report-li" style={{ fontSize: '0.9rem', color: 'var(--text-soft)', marginLeft: '16px', marginBottom: '6px', listStyleType: 'disc', lineHeight: '1.6' }}>{renderTextWithInlineFormatting(trimmed.substring(2))}</li>
      }
      if (/^\d+\.\s/.test(trimmed)) {
        const content = trimmed.replace(/^\d+\.\s/, '');
        return <li key={idx} className="report-ol" style={{ fontSize: '0.9rem', color: 'var(--text-soft)', marginLeft: '16px', marginBottom: '6px', listStyleType: 'decimal', lineHeight: '1.6' }}>{renderTextWithInlineFormatting(content)}</li>
      }
      if (trimmed === '') {
        return <div key={idx} style={{ height: '10px' }} />
      }
      return <p key={idx} className="report-p" style={{ fontSize: '0.9rem', color: 'var(--text-soft)', lineHeight: '1.6', margin: '0 0 10px 0', textAlign: 'justify' }}>{renderTextWithInlineFormatting(trimmed)}</p>
    })
  }

