  const exportJudgmentMastery = async (option: 'PDF' | 'DOCX') => {
    if (!judgmentAnalysis) {
      alert('Please analyze a judgment first.');
      return;
    }

    const caseName = judgmentAnalysis.title || 'Judgment Analysis';
    const safeName = caseName.replace(/[^\w\s-]/g, '').replace(/\s+/g, '_').slice(0, 80) || 'judgment_analysis';

    let reportText = `# JUDGMENT MASTERY REPORT: ${caseName}\n\n`;
    reportText += `## CASE SNAPSHOT\n`;
    reportText += `- Court: ${judgmentAnalysis.court || 'N/A'}\n`;
    reportText += `- Bench: ${judgmentAnalysis.bench || 'N/A'}\n`;
    reportText += `- Citation: ${judgmentAnalysis.citation || 'N/A'}\n`;
    reportText += `- Date of Judgment: ${judgmentAnalysis.dateOfJudgment || 'N/A'}\n`;
    reportText += `- Judges: ${(judgmentAnalysis.judges || []).join(', ') || 'N/A'}\n\n`;

    reportText += `## COGNITIVE ANALYSIS\n\n`;
    reportText += `### BACKGROUND FACTS\n${judgmentAnalysis.facts || 'N/A'}\n\n`;
    reportText += `### ISSUES FRAMED\n${(judgmentAnalysis.issues || []).map((issue: string, idx: number) => `${idx + 1}. ${issue}`).join('\n') || 'N/A'}\n\n`;
    reportText += `### PETITIONER ARGUMENTS\n${(judgmentAnalysis.argumentsPetitioner || []).map((arg: string) => `- ${arg}`).join('\n') || 'N/A'}\n\n`;
    reportText += `### RESPONDENT ARGUMENTS\n${(judgmentAnalysis.argumentsRespondent || []).map((arg: string) => `- ${arg}`).join('\n') || 'N/A'}\n\n`;
    reportText += `### REASONING & RATIO DECIDENDI\n${judgmentAnalysis.ratioDecidendi || 'N/A'}\n\n`;
    if (judgmentAnalysis.obiterDicta) {
      reportText += `### OBITER DICTA\n${judgmentAnalysis.obiterDicta}\n\n`;
    }
    reportText += `### FINAL HOLDING & DECISION\n${judgmentAnalysis.holding || 'N/A'}\n\n`;
    if (judgmentAnalysis.finalVerdict) {
      reportText += `### FINAL VERDICT\n${judgmentAnalysis.finalVerdict}\n\n`;
    }

    reportText += `## TIMELINE VIEW\n\n`;
    if (judgmentAnalysis.timeline && judgmentAnalysis.timeline.length > 0) {
      reportText += judgmentAnalysis.timeline.map((item: any) => `- ${item.year}: ${item.event}`).join('\n') + '\n\n';
    } else {
      reportText += `No timeline events identified.\n\n`;
    }

    reportText += `## CITATION NETWORK\n\n`;
    if (judgmentAnalysis.citationNetwork && judgmentAnalysis.citationNetwork.length > 0) {
      reportText += judgmentAnalysis.citationNetwork.map((cit: any) => `- ${cit.case} [${cit.relationship}]: ${cit.relevance}`).join('\n') + '\n\n';
    } else {
      reportText += `No citations identified.\n\n`;
    }

    if (judgmentRevisionNotes) {
      reportText += `## REVISION NOTES\n\n${judgmentRevisionNotes}\n\n`;
    }

    if (judgmentMootCourtKit) {
      reportText += `## MOOT COURT KIT\n\n${judgmentMootCourtKit}\n\n`;
    }

    if (judgmentAlternativeReasoning) {
      reportText += `## ALTERNATIVE JUDICIAL REASONING (IF I WERE THE JUDGE)\n\n${judgmentAlternativeReasoning}\n\n`;
    }

    const plainLines = reportText
      .replace(/\*\*(.*?)\*\*/g, '$1')
      .split('\n')
      .map((line: string) => line.trimEnd());

    if (option === 'PDF') {
      const { jsPDF } = await import('jspdf');
      const doc = new jsPDF({ unit: 'pt', format: 'a4' });
      const pageWidth = doc.internal.pageSize.getWidth();
      const pageHeight = doc.internal.pageSize.getHeight();
      const margin = 54;
      const gold: [number, number, number] = [176, 141, 87];
      const body: [number, number, number] = [31, 41, 55];

      doc.setFillColor(248, 250, 252);
      doc.rect(0, 0, pageWidth, pageHeight, 'F');
      doc.setDrawColor(...gold);
      doc.setLineWidth(2);
      doc.rect(36, 36, pageWidth - 72, pageHeight - 72);
      doc.setTextColor(...gold);
      doc.setFont('times', 'bold');
      doc.setFontSize(13);
      doc.text('LEGATRIXON', pageWidth / 2, 116, { align: 'center' });
      doc.setTextColor(17, 24, 39);
      doc.setFontSize(23);
      doc.text(doc.splitTextToSize(caseName, pageWidth - 150), pageWidth / 2, 188, { align: 'center' });
      doc.setFontSize(13);
      doc.text('Judgment Mastery Engine Report', pageWidth / 2, 270, { align: 'center' });
      doc.setFont('times', 'normal');
      doc.setFontSize(11);
      doc.text(`Court: ${judgmentAnalysis.court || 'N/A'}`, pageWidth / 2, 610, { align: 'center' });
      doc.text(`Citation: ${judgmentAnalysis.citation || 'N/A'}`, pageWidth / 2, 630, { align: 'center' });
      doc.text(`Generated: ${new Date().toLocaleDateString()}`, pageWidth / 2, 650, { align: 'center' });

      doc.addPage();
      let y = 58;
      const addPageIfNeeded = (needed = 18) => {
        if (y + needed > pageHeight - 54) {
          doc.addPage();
          y = 58;
        }
      };
      const addWrapped = (value: string, size = 11, bold = false, color: [number, number, number] = body, indent = 0) => {
        doc.setFont('times', bold ? 'bold' : 'normal');
        doc.setFontSize(size);
        doc.setTextColor(...color);
        const wrapped = doc.splitTextToSize(value || ' ', pageWidth - margin * 2 - indent);
        wrapped.forEach((line: string) => {
          addPageIfNeeded(size + 8);
          doc.text(line, margin + indent, y);
          y += size + 5;
        });
      };
      plainLines.forEach((line: string) => {
        const trimmed = line.trim();
        if (!trimmed) {
          y += 8;
          return;
        }
        if (trimmed.startsWith('# ')) {
          addWrapped(trimmed.slice(2), 18, true, gold);
          y += 10;
          return;
        }
        if (trimmed.startsWith('## ')) {
          addWrapped(trimmed.slice(3), 15, true, [17, 24, 39]);
          y += 6;
          return;
        }
        if (trimmed.startsWith('### ')) {
          addWrapped(trimmed.slice(4), 13, true, [30, 64, 175]);
          y += 4;
          return;
        }
        if (trimmed.startsWith('- ') || trimmed.startsWith('* ')) {
          addWrapped(`• ${trimmed.slice(2)}`, 11, false, body, 14);
          return;
        }
        addWrapped(trimmed.replace(/\*\*(.*?)\*\*/g, '$1').replace(/\*(.*?)\*/g, '$1'), 11, false, body);
      });
      doc.save(`${safeName}_mastery.pdf`);
      return;
    }

    if (option === 'DOCX') {
      const { Document, Packer, Paragraph, TextRun, HeadingLevel } = await import('docx');
      const children = [
        new Paragraph({ text: 'LEGATRIXON JUDGMENT MASTERY REPORT', heading: HeadingLevel.TITLE }),
        new Paragraph({ children: [new TextRun({ text: caseName, bold: true, size: 32 })] }),
        new Paragraph({ text: `Court: ${judgmentAnalysis.court || 'N/A'}` }),
        new Paragraph({ text: `Citation: ${judgmentAnalysis.citation || 'N/A'}` }),
        new Paragraph({ text: `Generated: ${new Date().toLocaleString()}` }),
        new Paragraph({ text: '' }),
        ...plainLines.map((line: string) => {
          if (line.startsWith('# ')) return new Paragraph({ text: line.slice(2), heading: HeadingLevel.HEADING_1 });
          if (line.startsWith('## ')) return new Paragraph({ text: line.slice(3), heading: HeadingLevel.HEADING_2 });
          if (line.startsWith('### ')) return new Paragraph({ text: line.slice(4), heading: HeadingLevel.HEADING_3 });
          return new Paragraph({ children: [new TextRun(line || ' ')] });
        }),
      ];
      const doc = new Document({ sections: [{ properties: {}, children }] });
      const blob = await Packer.toBlob(doc);
      downloadBlob(`${safeName}_mastery.docx`, blob, 'application/vnd.openxmlformats-officedocument.wordprocessingml.document');
      return;
    }
  }

  const fetchRevisionNotes = async (docId: string) => {
    setIsGeneratingRevisionNotes(true)
    try {
      const response = await fetch(`http://localhost:4000/api/v1/judgments/${docId}/revision-notes`, {
        method: 'POST',
        headers: { 'Authorization': `Bearer ${apiToken}` }
      })
      if (!response.ok) {
        throw new Error(await parseApiError(response, 'Failed to generate revision notes.'))
      }
      const data = await response.json()
      setJudgmentRevisionNotes(data.content)
      setJudgmentAnalysis((prev: any) => prev ? { ...prev, revisionNotes: data.content } : null)
    } catch (err: any) {
      alert(`Error generating revision notes: ${err.message}`)
    } finally {
      setIsGeneratingRevisionNotes(false)
    }
  }

  const fetchMootCourtKit = async (docId: string) => {
    setIsGeneratingMootKit(true)
    try {
      const response = await fetch(`http://localhost:4000/api/v1/judgments/${docId}/moot-court-kit`, {
        method: 'POST',
        headers: { 'Authorization': `Bearer ${apiToken}` }
      })
      if (!response.ok) {
        throw new Error(await parseApiError(response, 'Failed to generate moot court kit.'))
      }
      const data = await response.json()
      setJudgmentMootCourtKit(data.content)
      setJudgmentAnalysis((prev: any) => prev ? { ...prev, mootCourtKit: { content: data.content } } : null)
    } catch (err: any) {
      alert(`Error generating moot court kit: ${err.message}`)
    } finally {
      setIsGeneratingMootKit(false)
    }
  }

  // Auto-sync active document selections and load analysis on mount or tab select
  useEffect(() => {
    if (lexDocs.length > 0 && !selectedJudgmentDocId) {
      setSelectedJudgmentDocId(lexDocs[0].id)
    }
  }, [lexDocs, selectedJudgmentDocId])

  useEffect(() => {
    if (selectedLexDocId && selectedLexDocId !== 'all') {
      setSelectedJudgmentDocId(selectedLexDocId)
    }
  }, [selectedLexDocId])

  useEffect(() => {
    if (selectedJudgmentDocId && apiToken) {
      fetchJudgmentAnalysis(selectedJudgmentDocId)
    }
  }, [selectedJudgmentDocId, apiToken])

  // Universal dynamic legal markdown compiler to render premium LEGATRIXON cards
  const renderLegalMarkdown = (text: string, fallbackText: string = "Information not found in uploaded judgment") => {
    if (!text || !text.trim()) {
      return <div className="jme-not-found">{fallbackText}</div>;
    }

    const cleanLine = (str: string) => {
      return str
        .replace(/^[\s#*>-]+/, '')
        .replace(/\*\*|__/g, '')
        .replace(/\*|_/g, '')
        .replace(/`+/g, '')
        .trim();
    };

    const lines = text.split('\n');
    const elements: React.JSX.Element[] = [];
    let currentListItems: string[] = [];
    let tableRows: string[][] = [];
    let inTable = false;

    const flushList = (key: string | number) => {
      if (currentListItems.length > 0) {
        elements.push(
          <ol key={`list-${key}`} className="jme-numbered-list">
            {currentListItems.map((item, idx) => (
              <li key={idx} className="jme-list-item">
                <span className="jme-list-num">{idx + 1}.</span>
                <span className="jme-list-text">{item}</span>
              </li>
            ))}
          </ol>
        );
        currentListItems = [];
      }
    };

    const flushTable = (key: string | number) => {
      if (tableRows.length > 0) {
        const validRows = tableRows.filter(row => !row.every(cell => /^[-\s:|]+$/.test(cell)));
        if (validRows.length > 0) {
          const headers = validRows[0];
          const bodyRows = validRows.slice(1);
          elements.push(
            <div key={`table-wrapper-${key}`} className="jme-table-wrapper">
              <table className="jme-table">
                <thead>
                  <tr>
                    {headers.map((h, i) => <th key={i}>{cleanLine(h)}</th>)}
                  </tr>
                </thead>
                <tbody>
                  {bodyRows.map((row, rIdx) => (
                    <tr key={rIdx}>
                      {row.map((cell, cIdx) => <td key={cIdx}>{cleanLine(cell)}</td>)}
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          );
        }
        tableRows = [];
        inTable = false;
      }
    };

    lines.forEach((rawLine, index) => {
      const trimmed = rawLine.trim();

      if (trimmed.startsWith('|')) {
        if (!inTable) {
          flushList(index);
          inTable = true;
        }
        const cells = trimmed.split('|').map(c => c.trim()).filter((_, i, arr) => i > 0 && i < arr.length - 1);
        tableRows.push(cells);
        return;
      } else if (inTable) {
        flushTable(index);
      }

      if (trimmed.startsWith('- ') || trimmed.startsWith('* ') || /^\d+\.\s/.test(trimmed)) {
        flushTable(index);
        currentListItems.push(cleanLine(trimmed.replace(/^\d+\.\s/, '')));
        return;
      } else {
        flushList(index);
      }

      if (!trimmed) {
        elements.push(<div key={index} className="jme-spacer" />);
        return;
      }

      if (trimmed.startsWith('# ') || trimmed.startsWith('## ') || trimmed.startsWith('### ') || trimmed.startsWith('#### ')) {
        const depth = trimmed.match(/^#+/)?.[0].length || 1;
        const cleanTitle = cleanLine(trimmed);
        elements.push(
          <div key={index} className={`jme-heading-title depth-${depth}`}>
            {cleanTitle}
          </div>
        );
        return;
      }

      if (trimmed.startsWith('>')) {
        elements.push(
          <div key={index} className="jme-blockquote">
            {cleanLine(trimmed)}
          </div>
        );
        return;
      }

      if (trimmed === '---' || trimmed === '***') {
        elements.push(<hr key={index} className="jme-divider" />);
        return;
      }

      elements.push(
        <p key={index} className="jme-para">
          {trimmed.split(/(\*\*.*?\*\*)/g).map((part, pIdx) => {
            if (part.startsWith('**') && part.endsWith('**')) {
              return <strong key={pIdx} className="jme-strong">{part.slice(2, -2)}</strong>;
            }
            return part;
          })}
        </p>
      );
    });

    flushList('final');
    flushTable('final');

    return <div className="jme-rendered-markdown">{elements}</div>;
  }

  const renderGroundingRefs = (field: string) => {
    if (!judgmentAnalysis || !judgmentAnalysis.sourceChunkRefs) return null;
    const refs = judgmentAnalysis.sourceChunkRefs.filter((ref: any) => ref.field === field);
    if (refs.length === 0) return null;
    return (
      <div className="jme-grounding-section">
        <h5 style={{ fontWeight: '700', fontSize: '0.82rem', textTransform: 'uppercase', color: 'var(--gold)', marginBottom: '6px' }}>Source Grounding References</h5>
        <div style={{ display: 'flex', flexDirection: 'column', gap: '6px' }}>
          {refs.map((ref: any, idx: number) => (
            <div key={idx} className="jme-ref-block">
              <strong>Page {ref.pageNumber} (Chunk {ref.chunkIndex})</strong>
              <p style={{ margin: '2px 0 0', fontSize: '0.78rem', color: 'var(--text-soft)', fontStyle: 'italic' }}>"{ref.excerpt}"</p>
            </div>
          ))}
        </div>
      </div>
    );
  };

  // toggleTask is now managed inside AcademicNavigator.

  // Handle active quiz answers
  const handleQuizAnswer = (qIdx: number, oIdx: number) => {
    if (showQuizFeedback) return
    setSelectedQuizAnswers(prev => ({ ...prev, [qIdx]: oIdx }))
  }

  const submitQuiz = () => {
    let correctCount = 0
    quizQuestions.forEach((q, idx) => {
      if (selectedQuizAnswers[idx] === q.correct) {
        correctCount++
      }
    })
    const score = quizQuestions.length > 0 ? Math.round((correctCount / quizQuestions.length) * 100) : 0
    setQuizScore(score)
    setShowQuizFeedback(true)
    setMasteryScore(Math.min(100, masteryScore + 5))
    if (activeLexDoc?.id && activeStudyForge?.quizQuestions?.length) {
      fetch(`http://localhost:4000/api/v1/notebook/documents/${activeLexDoc.id}/study-forge/quiz-attempt`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${apiToken}`
        },
        body: JSON.stringify({ answers: selectedQuizAnswers })
      })
        .then(async (response) => {
          if (!response.ok) throw new Error(await parseApiError(response, 'Failed to persist quiz attempt.'))
          return response.json()
        })
        .then((studyForge) => {
          setLexDocs(prev => prev.map(doc => doc.id === activeLexDoc.id ? { ...doc, studyForge } : doc))
        })
        .catch((err) => console.warn('[Smart Study Forge] Quiz progress persistence failed.', err))
    }
  }

  // Reset active quiz
  const resetQuiz = () => {
    setSelectedQuizAnswers({})
    setQuizScore(null)
    setShowQuizFeedback(false)
  }

  const uniqueMatchesFromText = (text: string, regex: RegExp, limit: number) =>
    Array.from(new Set((text.match(regex) || []).map((match) => match.trim())))
      .filter(Boolean)
      .slice(0, limit)

  const shortenStudyText = (value: string, limit: number) => {
    const trimmed = String(value || '').replace(/\s+/g, ' ').trim()
    return trimmed.length > limit ? `${trimmed.slice(0, limit - 3)}...` : trimmed
  }

  const findStudySentence = (sentences: string[], term: string) =>
    sentences.find((sentence) => sentence.toLowerCase().includes(term.toLowerCase())) || term

  const studyForgeKey = (value: string) =>
    String(value || '')
      .toLowerCase()
      .replace(/[^a-z0-9]+/g, ' ')
      .replace(/\b(?:according|uploaded|document|which|what|from|this|that|should|remembered|source|excerpt)\b/g, ' ')
      .replace(/\s+/g, ' ')
      .trim()
      .slice(0, 180)

  const uniqueStudyLines = (lines: string[]) => {
    const seen = new Set<string>()
    return lines.filter((line) => {
      const key = studyForgeKey(line)
      if (!key || seen.has(key)) return false
      seen.add(key)
      return true
    })
  }

  const extractStudyTopic = (sentence: string) => {
    const legalRef = sentence.match(/\b(?:Article|Section)\s+\d+[A-Z]?(?:\(\d+\))?/i)
    if (legalRef) return legalRef[0]
    return shortenStudyText(sentence.replace(/[^a-zA-Z0-9\s]/g, ' '), 48) || 'document concept'
  }

  const extractDefinitionStudyTopic = (line: string) => {
    const compact = shortenStudyText(line.replace(/\s+/g, ' ').trim(), 140)
    const quoted = compact.match(/["â€œ']([^"â€']{3,80})["â€']/)
    if (quoted) return quoted[1].trim()
    const meansMatch = compact.match(/\b([A-Z][A-Za-z0-9 ,()/-]{2,80}?)\s+(?:means|refers to|is defined as)\b/i)
    if (meansMatch) return shortenStudyText(meansMatch[1].replace(/^(the|a|an)\s+/i, '').trim(), 70)
    const legalRef = compact.match(/\b(?:Article|Section|Part|Schedule)\s+[A-Za-z0-9()/-]+/i)
    if (legalRef) return legalRef[0]
    return extractStudyTopic(compact)
  }

  const buildStudyDistractors = (sentences: string[], source: string, count: number) => {
    const distractors = sentences
      .filter((sentence) => sentence !== source)
      .map((sentence) => shortenStudyText(sentence, 120))
      .filter(Boolean)
      .slice(0, count)
    while (distractors.length < count) {
      distractors.push(shortenStudyText(sentences[distractors.length % sentences.length] || source, 120))
    }
    return distractors
  }

  const buildLocalStudyForgeFromText = (text: string, docName: string) => {
    const normalized = text.replace(/\s+/g, ' ').trim()
    const sentences = normalized
      .split(/(?<=[.!?])\s+/)
      .map((sentence) => sentence.trim())
      .filter((sentence) => sentence.length >= 45 && sentence.length <= 320)

    if (!sentences.length) {
      throw new Error('The uploaded document text is too short to generate study assets.')
    }

    const articles = uniqueMatchesFromText(normalized, /\bArticle\s+\d+[A-Z]?(?:\(\d+\))?(?:\([a-z]\))?/gi, 12)
    const sections = uniqueMatchesFromText(normalized, /\bSection\s+\d+[A-Z]?(?:\(\d+\))?/gi, 12)
    const cases = uniqueMatchesFromText(normalized, /\b[A-Z][A-Za-z.&() ]+\s+v(?:s\.?|ersus)?\s+[A-Z][A-Za-z.&() ]+(?:\(\d{4}\))?/g, 10)
    const definitionLines = uniqueStudyLines(sentences.filter((sentence) => /\bmeans\b|\bdefined as\b|\brefers to\b/i.test(sentence))).slice(0, 8)
    const targetCount = Math.min(20, Math.max(10, sentences.length))
    const principleLines = uniqueStudyLines(sentences.filter((sentence) => /\bheld\b|\bprinciple\b|\bdoctrine\b|\bratio\b|\brequires\b|\bmust\b|\bshall\b/i.test(sentence))).slice(0, 12)
    const factLines = uniqueStudyLines(sentences.filter((sentence) => /\bfact\b|\bpetitioner\b|\brespondent\b|\bappellant\b|\bcourt\b|\bcontract\b|\bagreement\b|\bconstitution\b|\bamendment\b|\bgovernment\b/i.test(sentence))).slice(0, 10)

    const flashcards: Array<{ id: string; category: string; q: string; a: string; sourceExcerpt: string; mastery: number; reviews: number; nextReviewAt: null }> = []
    const usedQuestions = new Set<string>()
    const usedAnswers = new Set<string>()
    const addCard = (category: string, q: string, a: string) => {
      if (!q || !a || flashcards.length >= 20) return
      const questionKey = studyForgeKey(q)
      const answerKey = studyForgeKey(a)
      if (usedQuestions.has(questionKey) || usedAnswers.has(answerKey)) return
      usedQuestions.add(questionKey)
      usedAnswers.add(answerKey)
      flashcards.push({
        id: `fc_${flashcards.length + 1}`,
        category,
        q,
        a,
        sourceExcerpt: a,
        mastery: 0,
        reviews: 0,
        nextReviewAt: null,
      })
    }

    definitionLines.forEach((line) => addCard('Definition', `Define or explain this term from the uploaded document: ${extractDefinitionStudyTopic(line)}`, line))
    articles.forEach((article) => addCard('Article', `According to the uploaded document, what is stated in the passage mentioning ${article}?`, findStudySentence(sentences, article)))
    sections.forEach((section) => addCard('Section', `According to the uploaded document, what is stated in the passage mentioning ${section}?`, findStudySentence(sentences, section)))
    cases.forEach((caseName) => addCard('Case Law', `According to the uploaded document, why is ${caseName} relevant?`, findStudySentence(sentences, caseName)))
    principleLines.forEach((line) => addCard('Principle', `What principle is tested by: "${shortenStudyText(line, 70)}"?`, line))
    factLines.forEach((line) => addCard('Important Fact', `What important fact should you remember from: "${shortenStudyText(line, 70)}"?`, line))

    while (flashcards.length < targetCount) {
      const line = sentences.find((sentence) => !usedAnswers.has(studyForgeKey(sentence))) || sentences[flashcards.length % sentences.length]
      if (usedAnswers.has(studyForgeKey(line))) break
      addCard('Important Fact', `What is the key takeaway from this passage: "${shortenStudyText(line, 70)}"?`, line)
    }

    const quizSources = [...principleLines, ...factLines, ...sentences]
    while (quizSources.length < targetCount) {
      quizSources.push(sentences[quizSources.length % sentences.length])
    }
    const quizQuestions = quizSources.slice(0, targetCount).map((source, index) => {
      const types = ['Concept Based', 'Case Based', 'Fact Based', 'Scenario Based']
      const correct = index % 4
      const answer = shortenStudyText(source, 130)
      const options = [answer, ...buildStudyDistractors(sentences, source, 3)].slice(0, 4)
      const rotated = options.slice(1)
      rotated.splice(correct, 0, answer)
      return {
        type: types[index % types.length],
        topic: extractStudyTopic(source),
        q: `${types[index % types.length]}: According to the uploaded document, which statement is correct about ${extractStudyTopic(source)}?`,
        opts: rotated,
        correct,
        exp: `Source excerpt: ${source}`,
      }
    })

    const keyPoints = sentences.slice(0, 10).map((sentence) => `- ${sentence}`).join('\n')
    const revisionNotes = [
      `# Revision Notes: ${docName}`,
      '',
      '## Exam Focused Notes',
      keyPoints,
      '',
      '## Important Cases',
      cases.length ? cases.map((item) => `- ${item}`).join('\n') : '- No case names were explicitly detected in the uploaded text.',
      '',
      '## Important Articles',
      articles.length ? articles.map((item) => `- ${item}`).join('\n') : '- No constitutional articles were explicitly detected in the uploaded text.',
      '',
      '## Important Sections',
      sections.length ? sections.map((item) => `- ${item}`).join('\n') : '- No statutory sections were explicitly detected in the uploaded text.',
      '',
      '## Critical Concepts',
      principleLines.slice(0, 6).map((sentence) => `- ${sentence}`).join('\n') || keyPoints,
    ].join('\n')

    const onePageNotes = [
      `# One Page Quick Revision: ${docName}`,
      '',
      '## High Yield Concepts',
      ...sentences.slice(0, 5).map((sentence) => `- ${sentence}`),
      '',
      '## Most Important Cases',
      ...(cases.length ? cases.slice(0, 5).map((item) => `- ${item}`) : ['- Not expressly detected in the uploaded text.']),
      '',
      '## Most Important Articles / Sections',
      ...[...articles.slice(0, 5), ...sections.slice(0, 5)].map((item) => `- ${item}`),
      '',
      '## Exam Quick Revision Sheet',
      ...principleLines.slice(0, 5).map((sentence) => `- ${sentence}`),
    ].join('\n')

    return {
      status: 'Ready',
      generationStatus: 'Generated from uploaded document chunks in the browser because the backend generation route is not available.',
      sourceDocument: docName,
      flashcards,
      quizQuestions,
      revisionNotes,
      onePageNotes,
      generatedAt: new Date().toISOString(),
      progress: { masteryScore: 0, quizAccuracy: 0, completion: 0, weakTopics: [], flashcardsReviewed: 0 },
    }
  }

  const generateStudyForgeFromChunksInBrowser = async (docId: string, docName: string) => {
    const chunksResponse = await fetch(`http://localhost:4000/api/v1/notebook/documents/${docId}/chunks`, {
      headers: { 'Authorization': `Bearer ${apiToken}` }
    })
    if (!chunksResponse.ok) {
      throw new Error(await parseApiError(chunksResponse, 'Could not fetch extracted document chunks.'))
    }
    const chunks = await chunksResponse.json()
    const text = Array.isArray(chunks) ? chunks.map((chunk: any) => chunk.text).join('\n\n') : ''
    const studyForge = buildLocalStudyForgeFromText(text, docName)
    saveLocalStudyForge(docId, studyForge)
    return studyForge
  }

  const refreshOrGenerateStudyForge = async (docId: string, docName: string) => {
    setStudyForgeStatusText('Checking generated study assets for the active document...')

    const docResponse = await fetch(`http://localhost:4000/api/v1/notebook/documents/${docId}`, {
      headers: { 'Authorization': `Bearer ${apiToken}` }
    })

    if (docResponse.ok) {
      const latestDoc = await docResponse.json()
      const mappedDoc = mapLexDoc(latestDoc)
      setLexDocs(prev => prev.map(doc => doc.id === docId ? { ...doc, ...mappedDoc } : doc))

      if (!studyForgeNeedsAssets(mappedDoc.studyForge)) {
        setStudyForgeStatusText('Study assets loaded from the uploaded document.')
        return mappedDoc.studyForge
      }
    }

    setStudyForgeStatusText('Generating study assets from the uploaded document...')
    try {
      const response = await fetch(`http://localhost:4000/api/v1/notebook/documents/${docId}/study-forge/generate`, {
        method: 'POST',
        headers: { 'Authorization': `Bearer ${apiToken}` }
      })
      if (response.ok) {
        const studyForge = await response.json()
        setLexDocs(prev => prev.map(doc => doc.id === docId ? { ...doc, studyForge } : doc))
        setStudyForgeStatusText('Study assets generated from the uploaded document.')
        return studyForge
      }
    } catch (err) {
      console.warn('[Smart Study Forge] Backend generation unavailable, using extracted chunks.', err)
    }

    const studyForge = await generateStudyForgeFromChunksInBrowser(docId, docName)
    setLexDocs(prev => prev.map(doc => doc.id === docId ? { ...doc, studyForge } : doc))
    setStudyForgeStatusText('Study assets generated from extracted document chunks.')
    return studyForge
  }

  const renderStudyNote = (text: string, emptyText: string) => {
    if (!text.trim()) {
      return <p style={{ margin: 0, color: 'var(--text-soft)' }}>{emptyText}</p>
    }

    return text.split('\n').map((rawLine, index) => {
      const line = rawLine.trim()
      if (!line) return <div key={index} style={{ height: '8px' }} />

      if (line.startsWith('# ')) {
        return (
          <h2 key={index} style={{ margin: '0 0 10px', fontSize: '1.08rem', color: 'var(--gold)', fontWeight: 800 }}>
            {line.replace(/^#\s+/, '')}
          </h2>
        )
      }

      if (line.startsWith('## ')) {
        return (
          <h3 key={index} style={{ margin: '16px 0 8px', fontSize: '0.94rem', color: 'var(--text)', fontWeight: 800, borderBottom: '1px solid rgba(245,193,79,0.22)', paddingBottom: '6px' }}>
            {line.replace(/^##\s+/, '')}
          </h3>
        )
      }

      if (line.startsWith('- ')) {
        return (
          <div key={index} style={{ display: 'grid', gridTemplateColumns: '18px 1fr', gap: '8px', alignItems: 'start', margin: '7px 0', padding: '8px 10px', borderRadius: '8px', background: 'rgba(255,255,255,0.025)', border: '1px solid rgba(255,255,255,0.06)' }}>
            <span style={{ color: 'var(--gold)', fontWeight: 900, lineHeight: 1.3 }}>â€¢</span>
            <span style={{ color: 'var(--text)', lineHeight: 1.55 }}>{line.replace(/^-\s+/, '')}</span>
          </div>
        )
      }

      return (
        <p key={index} style={{ margin: '6px 0', color: 'var(--text)', lineHeight: 1.6 }}>
          {line}
        </p>
      )
    })
  }

  const generateStudyForgeForActiveDoc = async () => {
    if (!activeLexDoc) {
      setStudyForgeStatusText('Upload a PDF, DOCX, or TXT document before generating study assets.')
      return
    }
    if (!isLexDocIndexed(activeLexDoc)) {
      setStudyForgeStatusText('Document processing is still running. Study assets can be generated after indexing finishes.')
      return
    }

    setIsStudyForgeGenerating(true)
    setStudyForgeStatusText('Generating flashcards, MCQs, revision notes, and one-page notes from the active document...')
    setLexDocs(prev => prev.map(doc => doc.id === activeLexDoc.id ? {
      ...doc,
      studyForge: {
        status: 'Generating',
        generationStatus: 'Extracting text, chunking content, generating embeddings, storing context, and creating study assets.',
        generatedAt: null,
        sourceDocument: doc.name,
        flashcards: [],
        quizQuestions: [],
        revisionNotes: '',
        onePageNotes: '',
        progress: { masteryScore: 0, quizAccuracy: 0, completion: 0, weakTopics: [], flashcardsReviewed: 0 }
      }
    } : doc))

    try {
      const response = await fetch(`http://localhost:4000/api/v1/notebook/documents/${activeLexDoc.id}/study-forge/generate`, {
        method: 'POST',
        headers: { 'Authorization': `Bearer ${apiToken}` }
      })
      let studyForge
      if (response.ok) {
        studyForge = await response.json()
      } else {
        const apiError = await parseApiError(response, 'Study Forge generation failed.')
        setStudyForgeStatusText(`${apiError} Using extracted document chunks instead...`)
        studyForge = await generateStudyForgeFromChunksInBrowser(activeLexDoc.id, activeLexDoc.name)
      }
      setLexDocs(prev => prev.map(doc => doc.id === activeLexDoc.id ? { ...doc, studyForge } : doc))
      setStudyForgeStatusText('Study assets generated from the uploaded document.')
    } catch (err) {
      try {
        const studyForge = await generateStudyForgeFromChunksInBrowser(activeLexDoc.id, activeLexDoc.name)
        setLexDocs(prev => prev.map(doc => doc.id === activeLexDoc.id ? { ...doc, studyForge } : doc))
        setStudyForgeStatusText('Study assets generated from extracted document chunks.')
      } catch (fallbackErr) {
        setStudyForgeStatusText(fallbackErr instanceof Error ? fallbackErr.message : err instanceof Error ? err.message : 'Study Forge generation failed.')
      }
    } finally {
      setIsStudyForgeGenerating(false)
    }
  }

  const rateActiveFlashcard = async (rating: 'Hard' | 'Good' | 'Easy') => {
    if (!activeLexDoc || !flashcards.length) return
    const card = flashcards[activeDeckCard]
    const cardId = card?.id || card?.q
    setIsCardFlipped(false)
    setActiveDeckCard((activeDeckCard + 1) % flashcards.length)
    setLexDocs(prev => prev.map(doc => {
      if (doc.id !== activeLexDoc.id || !doc.studyForge) return doc
      const updatedCards = doc.studyForge.flashcards.map((item, index) => index === activeDeckCard ? {
        ...item,
        lastRating: rating,
        reviews: (item.reviews || 0) + 1,
        mastery: Math.min(100, (item.mastery || 0) + (rating === 'Hard' ? 0 : rating === 'Good' ? 8 : 14))
      } : item)
      return {
        ...doc,
        studyForge: {
          ...doc.studyForge,
          flashcards: updatedCards,
          progress: {
            ...(doc.studyForge.progress || {}),
            flashcardsReviewed: updatedCards.reduce((sum, item) => sum + (item.reviews || 0), 0)
          }
        }
      }
    }))

    try {
      const response = await fetch(`http://localhost:4000/api/v1/notebook/documents/${activeLexDoc.id}/study-forge/flashcards/${encodeURIComponent(cardId)}/rate`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${apiToken}`
        },
        body: JSON.stringify({ rating })
      })
      if (!response.ok) throw new Error(await parseApiError(response, 'Failed to persist flashcard rating.'))
      const studyForge = await response.json()
      setLexDocs(prev => prev.map(doc => doc.id === activeLexDoc.id ? { ...doc, studyForge } : doc))
    } catch (err) {
      console.warn('[Smart Study Forge] Flashcard progress persistence failed.', err)
    }
  }

  // Handle Moot Court simulated dialogues
  const handleMootSubmit = (e: React.FormEvent) => {
    e.preventDefault()
    if (!mootArg.trim()) return

    const newDialog = [...mootDialog, { role: 'user', text: mootArg }]
    setMootDialog(newDialog)
    const usertext = mootArg
    setMootArg('')
    setIsMooting(true)

    setTimeout(() => {
      let judgeReply = ""
      if (judgeTemperament === 'Hostile') {
        judgeReply = `Counsel, you rely heavily on broad assertions! Explain to this Bench how your argument on personal liberty does not completely bypass the procedural bounds of the Passport Act. Where is your authority?`
      } else if (judgeTemperament === 'Scholarly') {
        judgeReply = `A persuasive line of thought, Counsel. But how do you reconcile this with the precedent established in A.K. Gopalan? Does not a literal reading of "procedure established by law" validate the state's actions here?`
      } else {
        judgeReply = `I see. Please proceed to your second submission on the issue of Natural Justice.`
      }

      setMootDialog(prev => [...prev, { role: 'judge', text: judgeReply }])
      setIsMooting(false)

      // Calculate simulated scores
      const scoreWeight = usertext.length > 30 ? 88 : 72
      const scores = {
        confidence: Math.round(scoreWeight * 0.98),
        reasoning: Math.round(scoreWeight * 0.95),
        research: Math.round(scoreWeight * 0.92),
        manner: Math.round(scoreWeight * 0.96)
      }
      setMootScores(scores)
      const metadata = {
        temperament: judgeTemperament,
        advocacyScore: Math.round(Object.values(scores).reduce((sum, score) => sum + score, 0) / 4),
      }
      Promise.all(['AI Judge Session', 'Completed Simulation'].map((action) => fetch(`${settingsApiBase}/activity`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${apiToken}` },
        body: JSON.stringify({ module: 'Moot Court Suite', action, metadata }),
      }))).catch(() => undefined)
    }, 1500)
  }

